const QUESTIONS_CISSP_C1 = [
  { id:30101, domain:1, level:1, question:"Which pillar of the CIA triad ensures that information is only accessible to those who are authorized?", options:["A Availability, which guarantees that authorized users can access information and systems whenever they have a legitimate business need to do so","B Accountability, which ensures that all actions taken by users can be traced back to specific individuals through audit logs and non-repudiation mechanisms","C Integrity, which ensures that data remains accurate, complete, and unmodified during storage, processing, or transmission across systems and networks","D Confidentiality, which ensures that information is not disclosed to unauthorized individuals, processes, or devices, keeping sensitive data protected from exposure"], correct:3, explanation:"Confidentiality prevents unauthorized disclosure of information. Availability ensures access for authorized users. Integrity protects accuracy. Accountability/non-repudiation is important but not part of the CIA triad." },
  { id:30102, domain:2, level:1, question:"Which role is primarily responsible for determining the sensitivity classification level of a specific dataset?", options:["A The data owner, who is the business unit or individual accountable for the data and responsible for deciding its classification and handling requirements","B The system administrator, who configures access control lists and technical settings on the systems that store and process classified information","C The security officer, who approves all classification decisions made by business units and ensures they align with organizational classification policy","D The data custodian, who implements and maintains technical controls protecting the data as directed by the data owner and organizational policy"], correct:0, explanation:"The data owner is the business-side accountable party who determines classification. The custodian implements controls. The admin configures systems. The security officer advises but does not own the classification decision." },
  { id:30103, domain:1, level:2, question:"In qualitative risk analysis, risks are expressed using which type of measurement?", options:["A Quantitative financial values such as Annual Loss Expectancy and Single Loss Expectancy derived from asset valuation and threat frequency data","B Statistical probability distributions and Monte Carlo simulations that model uncertainty in threat frequency and impact across thousands of scenarios","C Descriptive subjective scales such as high, medium, and low, or color-coded heat maps that represent relative risk levels without precise dollar values","D Compliance scores and regulatory gap percentages calculated by comparing current controls against a recognized framework like NIST or ISO 27001"], correct:2, explanation:"Qualitative analysis uses subjective descriptive scales (high/medium/low). Quantitative uses financial values and formulas. Monte Carlo is a quantitative technique. Compliance scores are used in audits, not risk analysis." },
  { id:30104, domain:2, level:2, question:"What security concern arises when multiple low-sensitivity data elements are combined to reveal sensitive information?", options:["A Data remanence, which occurs when residual data persists on storage media after deletion and could be recovered using specialized forensic tools","B The inference problem in database systems, where query results allow users to deduce the values of data they are not directly authorized to view","C Data sovereignty, because combining data from multiple jurisdictions in one location subjects it to conflicting laws that may restrict its use","D The aggregation problem, where individually innocuous data elements can be combined to infer or expose sensitive information not evident from any single element"], correct:3, explanation:"The aggregation problem is about combining low-sensitivity data to create high-sensitivity composite information. The inference problem (B) is related but refers specifically to deducing values through queries. Data sovereignty and remanence are different concepts." },
  { id:30105, domain:1, level:1, question:"What is the primary purpose of the ISC² Code of Ethics for security professionals?", options:["A To specify the minimum number of continuing education credits that CISSP holders must earn each year to maintain their professional certification","B To define the legal liability framework governing how CISSP holders are held accountable when security breaches occur at their organizations","C To establish mandatory professional behavioral standards guiding ethical conduct and defining the responsibilities of ISC² certified members","D To outline the technical security standards that all CISSP holders must follow when designing and implementing security architectures for clients"], correct:2, explanation:"The ISC² Code of Ethics establishes professional behavioral standards. It is not a CPE requirement schedule, liability framework, or technical standard—it is a framework of ethical principles for professional conduct." },
  { id:30106, domain:2, level:1, question:"What is the primary purpose of data labeling in a classification program?", options:["A Data labeling creates metadata records in a central catalog so IT can locate, manage, and track all data assets across the enterprise infrastructure","B Data labeling automates tag insertion into network packets so that firewalls and DLP systems can apply different policies to different traffic types","C Data labels physically or digitally mark assets with their classification level so that handlers clearly understand the required protection and handling procedures","D Data labeling adds copyright and intellectual property notices to documents, providing legal protection against unauthorized use by competitors"], correct:2, explanation:"Data labeling marks assets so handlers know what protections to apply. Data catalogs, copyright notices, and network packet tagging are separate concepts not describing the purpose of classification labeling." },
  { id:30107, domain:1, level:2, question:"What distinguishes 'due care' from 'due diligence' in security governance?", options:["A Due diligence involves researching and understanding risks and obligations; due care means taking reasonable, ongoing actions to protect assets appropriately","B Due care is performed by auditors to verify compliance; due diligence is performed by security engineers when implementing new technical controls","C Due care and due diligence are interchangeable terms that both describe an organization's legal obligation to protect sensitive assets and data","D Due care refers to research and investigation activities performed before making security decisions; due diligence means implementing appropriate controls"], correct:0, explanation:"Due diligence is the research/assessment phase (understanding what to do). Due care is acting on that knowledge by implementing reasonable protections. They are complementary, not identical." },
  { id:30108, domain:2, level:3, question:"An organization needs to securely dispose of SSDs containing classified data. Why is degaussing inadequate for SSDs?", options:["A Degaussing is inadequate because SSDs are too physically large to fit inside standard industrial degaussing equipment used for magnetic media","B Degaussing is effective for magnetic tape and hard drives but produces excessive heat when applied to SSDs, causing fire and safety hazards","C Degaussing is inadequate because SSDs may retain data in over-provisioned areas and wear-leveling sectors that are not reachable by standard degaussing fields","D Degaussing is inadequate only for enterprise SSDs; consumer-grade SSDs can be reliably sanitized using standard magnetic degaussing procedures"], correct:2, explanation:"SSDs use flash memory (not magnetic storage), so degaussing has no effect on the actual data. Wear-leveling and over-provisioning also make software wiping unreliable. Physical destruction is the recommended approach." },
  { id:30109, domain:1, level:3, question:"When using the NIST Risk Management Framework, what is the correct sequence of steps?", options:["A Select, Categorize, Assess, Implement, Monitor, Authorize—prioritizing control selection before system categorization to save time in the process","B Implement, Assess, Categorize, Select, Authorize, Monitor—focusing on implementation first to address urgent threats before completing documentation","C Categorize, Select, Implement, Assess, Authorize, Monitor—beginning with categorizing systems and ending with continuous monitoring after authorization","D Assess, Categorize, Select, Implement, Authorize, Monitor—starting with risk assessment before categorizing information systems by impact level"], correct:2, explanation:"NIST RMF steps are: Prepare, Categorize, Select, Implement, Assess, Authorize, Monitor. The sequence beginning Categorize→Select→Implement→Assess→Authorize→Monitor correctly reflects the framework order." },
  { id:30110, domain:2, level:2, question:"What does 'tailoring' security controls mean in the context of NIST security frameworks?", options:["A Tailoring means adjusting selected controls through modifications, compensating alternatives, or supplemental additions to fit the specific operational environment","B Tailoring means selecting a subset of controls from a baseline catalog that apply to a specific system based on its environment and function","C Tailoring means reducing all security control requirements for low-impact systems to minimize implementation burden and operational overhead costs","D Tailoring means having an external auditor review and approve all security control selections before they can be officially documented in the SSP"], correct:0, explanation:"Tailoring adjusts selected controls to fit the environment—adding compensating controls, modifying parameters, or supplementing. Scoping (A) identifies applicable controls. Reducing requirements (C) is a risk decision. External approval (D) is authorization." },
  { id:30111, domain:1, level:1, question:"Which type of security control is an organizational security policy?", options:["A A technical control, because policies are implemented and enforced through automated security tools like SIEM systems and access control software","B A detective control, because policies help identify when violations occur by establishing the behavioral baseline against which activities are compared","C An administrative control, because a policy is a management-directed document that governs human behavior and organizational processes rather than technology","D A physical control, because policies must be printed and physically posted in the workplace to inform employees of their obligations and requirements"], correct:2, explanation:"Security policies are administrative controls—management directives governing behavior and process. Technical controls are software/hardware. Physical controls are tangible barriers. Detective vs. preventive is a separate classification axis." },
  { id:30112, domain:2, level:1, question:"What is the main security risk of 'data remanence' on enterprise storage media?", options:["A Data remanence increases storage costs because sectors containing residual data cannot be reallocated for new writes until full sanitization completes","B Data remanence forces organizations to keep media beyond its planned retention period, creating compliance violations with destruction schedule policies","C Data remanence causes data corruption over time, gradually degrading data integrity until affected files become unreadable and cannot be restored","D Residual data persisting on media after deletion could be recovered by unauthorized parties if the media is reused, sold, or improperly disposed of"], correct:3, explanation:"The primary risk is that sensitive data remains recoverable after deletion, allowing unauthorized access if media changes hands. Integrity degradation, storage costs, and retention scheduling are not the core security risk of remanence." },
  { id:30113, domain:1, level:2, question:"What is the primary function of a Chief Information Security Officer (CISO)?", options:["A Configuring technical security controls including firewalls, intrusion detection systems, and endpoint protection platforms across the organization","B Conducting vulnerability assessments and penetration tests to identify technical weaknesses and report findings to IT management for remediation","C Providing strategic leadership for the information security program and aligning security objectives with business goals while managing organizational risk","D Managing the security operations center team and directly overseeing daily incident detection and response activities across all organizational systems"], correct:2, explanation:"The CISO provides strategic leadership and aligns security with business objectives. SOC management, pen testing, and technical configuration are operational functions that typically report through the CISO." },
  { id:30114, domain:2, level:3, question:"Under GDPR, what is the maximum timeframe for notifying the supervisory authority after discovering a personal data breach?", options:["A 30 days from discovery, allowing the organization sufficient time to conduct a thorough investigation before making any regulatory notifications","B 90 days from discovery, providing enough time to assess the full scope and impact of the breach before notifying the supervisory authority","C 24 hours from discovery, if the breach is determined to involve special categories of personal data like health or financial information","D 72 hours from becoming aware of the breach, unless the breach is unlikely to result in a risk to the rights and freedoms of individuals"], correct:3, explanation:"GDPR Article 33 requires notification to the supervisory authority within 72 hours of becoming aware of a breach, unless unlikely to risk individuals' rights. The 72-hour clock runs from awareness, not discovery." },
  { id:30115, domain:1, level:3, question:"The Annual Loss Expectancy (ALE) is calculated using which formula?", options:["A ALE equals the total asset value divided by the number of threat events expected per year, giving an average per-threat exposure calculation","B ALE equals Asset Value multiplied by the Exposure Factor, providing the expected financial loss per occurrence of a specific threat event","C ALE equals Single Loss Expectancy multiplied by Annual Rate of Occurrence, representing the expected yearly financial loss from a specific threat","D ALE equals the Annualized Rate of Occurrence minus the exposure factor multiplied by the replacement cost of the compromised asset"], correct:2, explanation:"ALE = SLE × ARO. SLE = Asset Value × Exposure Factor. ALE is the expected annual loss from a specific threat, used to justify security control costs through cost-benefit analysis." },
  { id:30116, domain:2, level:2, question:"What is 'data minimization' as required by GDPR and similar privacy regulations?", options:["A Collecting and retaining only the minimum personal data necessary for the specified, legitimate processing purpose and not exceeding that amount","B Data minimization requires implementing the most stringent encryption available to reduce the potential impact of a breach on personal data","C Data minimization means reducing the number of employees with access to personal data by implementing role-based access controls across systems","D Data minimization requires organizations to compress PII databases using algorithms that reduce storage footprint while maintaining data availability"], correct:0, explanation:"Data minimization means only collecting what is strictly necessary for the stated purpose. It is a collection and retention principle, not about compression, encryption strength, or number of people with access." },
  { id:30117, domain:1, level:1, question:"Which of the following scenarios represents a violation of the 'separation of duties' principle?", options:["A A security analyst who monitors SIEM alerts and escalates incidents to a different incident response team for investigation and remediation","B A database administrator who is responsible for maintaining database systems but cannot approve their own access requests to sensitive schemas","C A single employee who is responsible for both initiating financial transactions and approving those same transactions in the accounting system","D A network engineer who configures routers but must submit change requests that are reviewed and approved by a separate change advisory board"], correct:2, explanation:"Separation of duties requires different people to initiate and approve transactions. Option C allows one person to both create and approve, enabling undetected fraud. The other scenarios correctly separate duties." },
  { id:30118, domain:2, level:1, question:"What is the difference between 'anonymization' and 'pseudonymization' of personal data?", options:["A Anonymization applies only to structured database records, while pseudonymization applies to unstructured documents and free-text data formats","B Anonymization is required by GDPR for all personal data at rest; pseudonymization is optional and used only as a best practice enhancement","C Anonymized data cannot be re-identified (irreversible), while pseudonymized data replaces identifiers with codes that can be reversed using a separate key","D Anonymization and pseudonymization are identical techniques that both permanently remove all identifying information from personal data records"], correct:2, explanation:"Anonymized data is irreversible—no longer personal data under GDPR. Pseudonymized data still constitutes personal data because re-identification is possible with the key. GDPR does not mandate anonymization of all data." },
  { id:30119, domain:1, level:2, question:"What is the primary purpose of a Business Impact Analysis (BIA)?", options:["A To create the disaster recovery procedures and assign technical recovery responsibilities to IT staff for execution during a declared disaster","B To document all IT assets and systems in the organization and assess their current security posture against recognized baseline frameworks","C To identify all threats that could affect the organization and calculate their Annual Loss Expectancy for quantitative risk analysis reporting","D To establish the recovery time and recovery point objectives for critical business functions and identify the impact of disruption on operations"], correct:3, explanation:"The BIA identifies critical business functions, determines MTD/RTO/RPO, and quantifies disruption impact. It drives BCP/DRP design. Threat identification is risk assessment. Asset documentation and DRP procedures are separate outputs." },
  { id:30120, domain:2, level:2, question:"What is the purpose of 'data masking' in enterprise security programs?", options:["A Data masking permanently deletes sensitive fields from database records before records are archived to long-term cold storage systems","B Data masking encrypts sensitive fields in databases to prevent unauthorized database administrators from reading data during routine maintenance","C Data masking applies column-level access controls in databases so that unauthorized users cannot see specific fields in query result sets","D Data masking replaces real sensitive values with realistic fictitious substitutes, typically used in development, testing, and training environments"], correct:3, explanation:"Data masking creates realistic but fictitious substitutes for use in non-production environments. Encryption is a different control. Deletion destroys data. Column-level security is a different database access control technique." },
  { id:30121, domain:1, level:3, question:"What is 'residual risk' after implementing security controls?", options:["A Residual risk is the initial inherent risk before any security controls are applied, representing maximum potential exposure to identified threats","B Residual risk is the portion of risk that has been transferred to a third party through cyber insurance or outsourcing contractual arrangements","C Residual risk is the risk associated with data remanence on decommissioned storage media that could be recovered by an unauthorized adversary","D Residual risk is the remaining risk after all applicable controls have been implemented, which management must then accept or further address"], correct:3, explanation:"Residual risk is what remains after controls are applied. Inherent risk is before controls. Transferred risk has moved to another party. Data remanence risk is a specific risk type, not the definition of residual risk." },
  { id:30122, domain:2, level:3, question:"What is 'privacy by design' and when should privacy controls be incorporated?", options:["A Privacy by design means adding privacy controls to existing systems after deployment and testing to avoid disrupting the development timeline","B Privacy by design is a GDPR Article 25 requirement mandating annual privacy impact assessments for all systems processing personal data","C Privacy by design requires using specific privacy-enhancing technologies exclusively, such as anonymization and pseudonymization, in all systems","D Privacy by design means proactively embedding privacy controls and principles into system design from inception rather than retrofitting them later"], correct:3, explanation:"Privacy by design (Ann Cavoukian) means proactively building privacy in from the start of system design. It's not about adding controls later, mandating specific technologies, or requiring annual assessments." },
  { id:30123, domain:1, level:1, question:"What is the primary goal of security awareness, training, and education (SATE) programs?", options:["A To reduce human error and improve security-conscious behavior by helping all employees recognize threats and understand their security responsibilities","B To create technical competency in security tools so that IT staff can independently manage security systems without relying on vendor support","C To train the security team on offensive techniques like penetration testing so they can better identify and remediate vulnerabilities in organizational systems","D To fulfill regulatory compliance requirements by documenting annual security training completion for all employees and contractors organization-wide"], correct:0, explanation:"SATE programs primarily aim to reduce human error and build security awareness in all personnel. Compliance documentation and technical training are secondary outcomes; the core goal is behavioral improvement." },
  { id:30124, domain:2, level:1, question:"What is the key distinction between 'data at rest' and 'data in transit'?", options:["A Data at rest is production operational data accessed daily, while data in transit is backup data transferred to offsite disaster recovery locations","B Data at rest is stored on media in databases or file systems; data in transit is actively moving across networks between systems or endpoints","C Data at rest is always encrypted and requires no additional protection, while data in transit is unencrypted and requires TLS or VPN protection","D Data at rest refers to archived historical data, while data in transit refers to data currently being migrated between storage systems"], correct:1, explanation:"Data at rest is stored data (databases, file systems, drives). Data in transit moves across networks. Data in use is actively being processed in memory. These states each require different security controls." },
  { id:30125, domain:1, level:2, question:"What does 'tone at the top' mean in the context of security governance?", options:["A Tone at the top refers to the technical security baselines configured at the top of the network architecture, such as core routers and perimeter firewalls","B Tone at the top refers to the financial auditing concept of CFO-level ethics and governance that cascades down through the finance organization","C Tone at the top means the security team sets priorities for the year and communicates them downward through the organization via formal briefings","D Tone at the top describes how senior management's visible commitment to security shapes organizational culture and drives adoption of security practices"], correct:3, explanation:"Tone at the top means executive leadership visibly champions security, influencing the entire organization's security culture. It's not technical configuration, security team communications, or solely a financial concept." },
  { id:30126, domain:2, level:2, question:"What is the primary objective of a data retention policy?", options:["A To specify encryption requirements that must be applied to all sensitive data categories while they are stored in organizational systems and archives","B To establish backup and recovery procedures ensuring that critical data can be restored within defined recovery time and recovery point objectives","C To define how long different data categories must be kept and when data should be securely destroyed after its useful and legally required life ends","D To identify which employees are authorized to access each data category based on their job function and documented need-to-know requirements"], correct:2, explanation:"Data retention policies define retention periods and destruction schedules. Encryption requirements, backup procedures, and access authorization are separate policy domains, each governed by their own policy instruments." },
  { id:30127, domain:1, level:3, question:"When evaluating whether to implement a security safeguard, which formula determines its economic value?", options:["A Safeguard value equals ALE before safeguard implementation minus ALE after safeguard implementation minus the annual cost of the safeguard itself","B Safeguard value equals the total replacement cost of all assets protected by the control divided by the probability of a successful threat event","C Safeguard value equals Asset Value multiplied by Exposure Factor, representing the maximum recoverable loss from a successful single threat event","D Safeguard value equals the Annual Rate of Occurrence multiplied by the safeguard cost, showing how often the control must prevent an incident to break even"], correct:0, explanation:"The cost-benefit formula is: (ALEbefore – ALEafter) – Annual Safeguard Cost = Safeguard Value. A positive value means the safeguard is economically justified. Asset Value × EF is SLE, not safeguard value." },
  { id:30128, domain:2, level:3, question:"What is 'information rights management' (IRM) and how does it protect data beyond the organization's perimeter?", options:["A IRM is a legal framework defining an organization's rights to own and protect data it creates, including trade secret and intellectual property protections","B IRM is a role-based access control model applied to records in enterprise content management systems, restricting access to authorized internal users only","C IRM refers to regulatory rights granted to individuals to control how their personal information is used by organizations that collect and process it","D IRM technology embeds access controls directly into documents and files, enforcing permissions on who can view, edit, copy, or forward content even outside the organization"], correct:3, explanation:"IRM (enterprise rights management) embeds controls in files, enforcing permissions even after files leave the organization's systems. It extends protection beyond the perimeter. The other options describe legal rights, internal RBAC, or privacy rights." },
  { id:30129, domain:1, level:1, question:"What is the primary difference between a 'policy' and a 'procedure' in the security governance hierarchy?", options:["A A policy applies only to senior management and executives; a procedure applies to all employees regardless of their organizational level and function","B A policy is a technical document specifying configuration requirements for systems; a procedure is a high-level management directive about organizational goals","C A policy is created externally by regulators and must be adopted verbatim; a procedure is internally created and may be customized to organizational needs","D A policy states high-level mandatory goals and organizational requirements; a procedure provides step-by-step operational instructions for implementing policy"], correct:3, explanation:"Policies state high-level mandatory goals; procedures are detailed step-by-step guides for implementing those goals. Standards fill in specific requirements; guidelines offer optional recommendations." },
  { id:30130, domain:2, level:1, question:"What is the primary purpose of a data inventory or data catalog in an enterprise?", options:["A A data inventory documents all hardware and software assets to support IT asset lifecycle management, procurement planning, and license compliance tracking","B A data catalog documents all backup copies of organizational data and tests restoration procedures to ensure recovery objectives can be consistently met","C A data inventory identifies what data exists, where it is stored, its classification level, and who is responsible for it, supporting governance and security","D A data catalog tracks all employee access request approvals and denials for sensitive systems, providing an audit trail for access governance reviews"], correct:2, explanation:"A data inventory/catalog maps what data exists, its location, classification, and ownership—foundational to data governance and security. Hardware inventory, access logs, and backup records are separate data management disciplines." },
  { id:30131, domain:1, level:2, question:"Why is 'mandatory vacation' considered a security control in personnel security programs?", options:["A Mandatory vacation requires employees to leave their roles temporarily, enabling detection of fraud or unauthorized activities through review by coverage personnel","B Mandatory vacation reduces employee burnout and improves morale, which indirectly reduces security risks caused by tired, disengaged staff making errors","C Mandatory vacation gives security teams unobstructed time to audit employee accounts and permissions without the employee interfering in the review","D Mandatory vacation ensures cross-training of staff, guaranteeing that multiple employees can perform each critical function to eliminate single points of failure"], correct:0, explanation:"Mandatory vacation is a fraud detection control: when an employee must leave, others handle their work and may uncover irregularities. Cross-training and security audits are related benefits but not the primary security rationale." },
  { id:30132, domain:2, level:2, question:"Under GDPR, what rights does an individual have regarding their personal data held by an organization?", options:["A GDPR grants individuals the right to access their data but only through formal legal processes requiring involvement of a data protection attorney","B Individuals have the right to request deletion only if the data was collected without explicit consent; data collected lawfully cannot be deleted on request","C Individuals have rights only to view their data and correct inaccuracies; deletion and portability rights are reserved for special categories of sensitive data","D Individuals have the right to access, rectify, erase, restrict processing, object to processing, and receive their data in a portable format under GDPR"], correct:3, explanation:"GDPR Articles 15-21 grant rights to access, rectification, erasure (right to be forgotten), restriction, objection, and portability. These apply broadly, not just to special category data or data collected without consent." },
  { id:30133, domain:1, level:3, question:"What is the key security challenge in supply chain risk management?", options:["A The primary supply chain risk is non-compliance with licensing terms by vendors, creating legal liability and audit exposure for the purchasing organization","B Hardware or software from third-party vendors may contain pre-inserted malicious code, backdoors, or counterfeit components before delivery to the organization","C Supply chain risks are exclusively financial in nature, arising from vendor insolvency that disrupts the delivery of critical technology products","D Supply chain risks arise primarily from employees sharing sensitive data through personal cloud storage services on corporate-managed devices"], correct:1, explanation:"Supply chain threats include pre-inserted malware, backdoors, and counterfeit components—unique risks from the procurement channel. Employee cloud sharing, vendor insolvency, and licensing compliance are different risk categories." },
  { id:30134, domain:2, level:3, question:"What is 'data sovereignty' and why does it create compliance challenges for multinational organizations?", options:["A Data sovereignty means sensitive data must remain within an organization's own data centers, making cloud adoption illegal in most countries and jurisdictions","B Data sovereignty means an organization owns all data it creates, creating challenges when employees use personal devices to access corporate information","C Data sovereignty means data is subject to the laws of the country where it is physically stored or processed, creating conflicts when nations have incompatible legal requirements","D Data sovereignty means governments can access any data stored within their territory, requiring full-disk encryption to protect corporate data from inspection"], correct:2, explanation:"Data sovereignty subjects data to national law where it physically resides. Multinationals face conflicting requirements (GDPR vs. US laws, Chinese cybersecurity law, etc.). It doesn't prohibit cloud use but requires jurisdiction management." },
  { id:30135, domain:1, level:1, question:"What does the term 'risk appetite' mean in organizational risk management?", options:["A Risk appetite is the precise dollar amount an organization allocates annually to its security budget to address identified technology risks","B Risk appetite describes the organization's current level of residual risk after all security controls have been selected and implemented across systems","C Risk appetite is a regulatory metric defined by oversight bodies specifying the maximum acceptable risk level for organizations in regulated industries","D Risk appetite refers to the level of risk an organization is willing to accept in pursuit of its strategic objectives before requiring further controls"], correct:3, explanation:"Risk appetite is the organizational stance—how much risk the board and leadership will accept in pursuing strategy. It's not a budget amount, current residual risk level, or regulatory metric." },
  { id:30136, domain:2, level:1, question:"What is the purpose of a clean desk policy in an organizational security program?", options:["A A clean desk policy requires employees to secure sensitive documents and media when workspaces are unattended, reducing unauthorized disclosure risk","B A clean desk policy requires IT staff to remove unused software from workstations regularly, reducing the attack surface and supporting system security","C A clean desk policy mandates that employees lock their screens when away from desks, preventing unauthorized access to active user sessions","D A clean desk policy ensures that workspaces are neat and organized, primarily supporting employee productivity and professional workplace standards"], correct:0, explanation:"Clean desk policies require securing sensitive materials when unattended—a confidentiality control. Screen locking is a related but separate control. Workspace organization is an HR/facilities concern, not the security purpose." },
  { id:30137, domain:1, level:2, question:"What is the primary purpose of a security charter in a governance program?", options:["A A security charter is the budget document defining financial resources allocated to the information security function each fiscal year","B A security charter is a memorandum of understanding between the organization and a regulatory body describing security compliance obligations","C A security charter defines the technical architecture of the security infrastructure, including network topology, toolset, and integration specifications","D A security charter formally establishes the security program's authority, scope, mission, responsibilities, and accountability within the organization"], correct:3, explanation:"A security charter gives the security function formal authority, defines scope and mission, and establishes accountability. It's not a technical architecture document, budget, or regulatory agreement." },
  { id:30138, domain:2, level:2, question:"What is the primary security challenge with BYOD (Bring Your Own Device) policies?", options:["A BYOD programs increase IT support costs due to device diversity, making it more expensive to troubleshoot and secure personal devices consistently","B BYOD devices are generally slower than corporate-issued devices, creating performance problems when users access large classified data repositories remotely","C The organization lacks full control over personally owned devices, making it difficult to enforce data classification handling requirements and security controls","D BYOD devices use consumer hardware lacking physical security features required for handling sensitive corporate information in the workplace"], correct:2, explanation:"The core challenge is lack of organizational control over personal devices, hindering enforcement of data handling and security policies. Performance, support costs, and hardware grades are real but secondary to the control challenge." },
  { id:30139, domain:1, level:3, question:"What does 'scoping' mean when applying NIST security control baselines?", options:["A Scoping means defining geographic boundaries for cloud deployments to ensure data sovereignty requirements are met under applicable national laws","B Scoping means reducing all security controls for lower-impact systems to minimize implementation burden and free up resources for higher-priority systems","C Scoping identifies which controls from a baseline are applicable to a specific system based on its unique characteristics, environment, and function","D Scoping refers to encrypting data in scope for compliance audits to prevent auditors from accessing raw sensitive records during assessments"], correct:2, explanation:"Scoping determines which baseline controls apply to a specific system. Tailoring then adjusts those controls. Scoping is not about reducing controls arbitrarily, encrypting audit data, or geographic deployment decisions." },
  { id:30140, domain:2, level:3, question:"What is 'crypto-shredding' and when is it particularly useful for data destruction?", options:["A Crypto-shredding encrypts all data on a storage medium and then destroys the encryption keys, making remaining ciphertext effectively unreadable","B Crypto-shredding applies cryptographic hash functions to verify that all data sectors have been successfully overwritten during the sanitization process","C Crypto-shredding physically destroys cryptographic hardware like HSMs and smart cards to prevent adversaries from extracting stored encryption keys","D Crypto-shredding uses multi-pass cryptographic random number generators to overwrite storage sectors more effectively than deterministic wipe patterns"], correct:0, explanation:"Crypto-shredding (cryptographic erasure) pre-encrypts data and destroys keys—particularly useful for cloud storage and SSDs where physical destruction isn't practical. It renders ciphertext inaccessible without requiring physical media destruction." },
  { id:30141, domain:1, level:1, question:"What is the primary difference between a 'threat' and a 'vulnerability' in risk terminology?", options:["A A threat is quantifiable in financial terms using ALE calculations, while a vulnerability is a qualitative assessment of system weakness and exposure","B A threat is a weakness in a system that can be exploited, while a vulnerability is the likelihood that the exploitation will actually cause harm","C A threat is a potential cause of harm (actor, event, or circumstance), while a vulnerability is a weakness in a system or control that could be exploited","D A threat is always an intentional malicious act by a human adversary, while a vulnerability can include both deliberate attacks and accidental failures"], correct:2, explanation:"A threat is a potential cause of harm (threat agent + event). A vulnerability is a weakness. Risk arises from threats exploiting vulnerabilities. Threats can be accidental/natural, not just intentional human actors." },
  { id:30142, domain:2, level:1, question:"What is 'Digital Rights Management' (DRM)?", options:["A DRM is a database access control technique that restricts which users can read, modify, or delete records in enterprise information systems","B DRM is a regulatory framework granting creators exclusive legal rights to their original works and preventing unauthorized reproduction or distribution","C DRM is an organizational policy restricting employee access to external websites and cloud storage services on corporate-managed networks","D DRM refers to technologies that control how digital content is accessed, used, copied, modified, or distributed after delivery to end users"], correct:3, explanation:"DRM uses technology to control use, copying, and distribution after delivery. Copyright (B) is the legal framework. Web filtering (C) is a network control. Database access control (A) is a different security domain." },
  { id:30143, domain:1, level:2, question:"What is the role of a 'risk register' in an organizational risk management program?", options:["A A risk register is a financial reserve account set aside to cover potential losses from identified high-probability security incidents and breaches","B A risk register is a regulatory compliance filing submitted to oversight bodies documenting all identified organizational risks on an annual basis","C A risk register is a technical log generated by SIEM systems recording all security events that represent potential risks to organizational systems","D A risk register provides a centralized documented inventory of identified risks, assessments, owners, treatment decisions, and current status for ongoing management"], correct:3, explanation:"A risk register documents identified risks, their assessments, owners, and treatments for ongoing management. It's not a regulatory submission, SIEM log, or financial account." },
  { id:30144, domain:2, level:2, question:"What distinguishes data 'owners' from data 'stewards' in a data governance program?", options:["A Data owners and data stewards are identical roles, both referring to the business executive who makes all decisions about data classification and handling","B Data owners make policy and classification decisions about data; data stewards manage data quality, metadata standards, and day-to-day governance processes","C Data owners have read-only oversight access; data stewards have full operational access to create, read, update, and delete data in managed systems","D Data owners manage database hardware and storage infrastructure; data stewards manage business value, classification decisions, and data policy enforcement"], correct:1, explanation:"Data owners are accountable business parties who determine classification and policy. Data stewards manage quality, metadata, and governance processes. These are complementary, distinct roles within data governance." },
  { id:30145, domain:1, level:3, question:"What is the primary limitation of quantitative risk analysis compared to qualitative approaches?", options:["A Quantitative analysis is only accepted by government regulators, while commercial organizations must use qualitative methods for internal reporting purposes","B Quantitative analysis cannot be used to prioritize risks or compare different threat scenarios, limiting its practical usefulness in security planning","C Quantitative analysis produces subjective results that different analysts interpret differently, making it difficult to compare assessments across teams","D Quantitative analysis requires significant time, detailed data, specialized expertise, and is often difficult to complete accurately for many threat types"], correct:3, explanation:"Quantitative analysis requires accurate data (asset values, threat frequencies, exposure factors) that may be hard to obtain. It's time-consuming and expertise-intensive. Qualitative is faster and cheaper but less precise." },
  { id:30146, domain:2, level:3, question:"What is the 'shared responsibility model' for security in cloud computing environments?", options:["A The shared responsibility model divides security obligations: providers secure physical infrastructure and hypervisors; customers secure their data, applications, and access management","B In the shared model, the cloud provider takes full responsibility for all security aspects including data classification, access management, and encryption","C The shared responsibility model means security costs are split 50/50 between provider and customer, with liability divided equally for any breach events","D In the shared model, the customer is responsible for all security including physical data center security, network infrastructure, and hypervisor patching"], correct:0, explanation:"Providers secure infrastructure (physical, network, hypervisor). Customers secure their data, identities, and applications. Responsibility varies by service model (IaaS/PaaS/SaaS) but customers always own their data." },
  { id:30147, domain:1, level:1, question:"Which law primarily governs the protection of protected health information (PHI) in the United States?", options:["A The Health Insurance Portability and Accountability Act (HIPAA) sets standards for protecting PHI held by covered entities and their business associates","B The Children's Online Privacy Protection Act (COPPA) protects health information collected from children under 13 by websites and online services","C The Gramm-Leach-Bliley Act (GLBA) governs the protection of health information held by financial institutions and insurers providing health coverage","D The Sarbanes-Oxley Act (SOX) requires healthcare organizations to maintain accurate financial records and implement internal controls for auditing"], correct:0, explanation:"HIPAA protects PHI for covered entities (providers, payers, clearinghouses) and business associates. GLBA covers financial data. SOX covers public company financial reporting. COPPA protects children's online data." },
  { id:30148, domain:2, level:1, question:"What is the primary purpose of a records management policy?", options:["A A records management policy establishes rules for creating, maintaining, retaining, protecting, and disposing of organizational records to meet legal and business needs","B A records management policy identifies employees authorized to create official organizational records and specifies approval workflows for record submission","C A records management policy defines technical backup schedules and restoration procedures for all systems containing organizational records and data","D A records management policy specifies digital signature requirements for electronically executed documents to ensure their legal enforceability in court"], correct:0, explanation:"Records management policies govern the full record lifecycle—creation through disposal—to meet legal, regulatory, and business requirements. Backup procedures, e-signatures, and creation authority are separate topics." },
  { id:30149, domain:1, level:2, question:"What is 'defense in depth' in security architecture?", options:["A Defense in depth places all critical security controls at the network perimeter to stop threats before they can reach internal systems and data","B Defense in depth uses multiple overlapping security layers so that if one control fails, additional layers continue to provide protection against threats","C Defense in depth means using only the most sophisticated and expensive security controls to provide maximum protection for the most critical assets","D Defense in depth requires training every employee in the organization so that human awareness forms a deep, resilient barrier against social engineering"], correct:1, explanation:"Defense in depth uses multiple overlapping layers of controls (preventive, detective, corrective) so single control failure doesn't result in complete compromise. It's not about most expensive controls or perimeter-only defense." },
  { id:30150, domain:2, level:2, question:"What is the purpose of Data Loss Prevention (DLP) technology?", options:["A DLP technology provides backup and recovery capabilities ensuring that sensitive data can be restored quickly after accidental deletion by authorized users","B DLP technology monitors system performance and network bandwidth to detect large data transfers that could indicate unauthorized internal movement of data","C DLP technology monitors and controls the movement of sensitive data to prevent unauthorized disclosure, exfiltration, or accidental leakage from the organization","D DLP technology scans systems for malware capable of stealing sensitive data and removes threats before data exfiltration operations can succeed"], correct:2, explanation:"DLP monitors and controls data movement to prevent unauthorized disclosure. Performance monitoring, backup/recovery, and malware scanning are separate security technology categories with different purposes." },
  { id:30151, domain:1, level:3, question:"What is 'risk transference' and how does it reduce an organization's financial exposure?", options:["A Risk transference eliminates the root cause of a risk by ceasing the activity that creates the exposure, removing the risk entirely from consideration","B Risk transference shifts the financial burden of a risk to another party—such as an insurer or contractual partner—reducing the organization's own monetary liability","C Risk transference formally documents that management accepts the risk and will absorb any resulting losses without purchasing additional insurance or controls","D Risk transference reduces the likelihood or impact of a risk through implementation of security controls, patches, or procedural safeguards and countermeasures"], correct:1, explanation:"Risk transference (cyber insurance, SLAs with liability clauses) shifts financial consequences to another party. Avoidance eliminates risk. Mitigation reduces risk. Acceptance absorbs risk." },
  { id:30152, domain:2, level:3, question:"What are the OECD Fair Information Practice Principles and why are they foundational to privacy frameworks globally?", options:["A The OECD principles are legally binding regulations that all member nations must implement into domestic law within two years of ratification","B The OECD principles (collection limitation, data quality, purpose specification, use limitation, security, openness, participation, accountability) established foundational privacy concepts adopted worldwide","C The OECD principles focus exclusively on financial data protection and apply only to banks and financial institutions in OECD member countries","D The OECD principles are specific technical security standards for encrypting personal data in transit and at rest in cross-border commerce systems"], correct:1, explanation:"The eight OECD Fair Information Practices established foundational privacy concepts that influenced GDPR, APEC Privacy Framework, and national privacy laws globally. They are guidelines, not legally binding regulations, and cover all personal data." },
  { id:30153, domain:1, level:1, question:"What is the 'principle of least privilege'?", options:["A Least privilege means privileged administrator accounts should be shared among team members rather than assigned to specific named individuals","B Least privilege means users and processes receive only the minimum permissions necessary to perform their legitimate functions and nothing beyond that","C Least privilege means the organization should license the minimum number of software seats needed, reducing costs while remaining in compliance","D Least privilege means all users should have identical access rights to ensure equitable treatment and prevent discrimination in access decisions"], correct:1, explanation:"Least privilege grants only the minimum access needed for legitimate functions. Shared accounts violate individual accountability. Equal access ignores need-to-know. Licensing optimization is a cost management topic." },
  { id:30154, domain:2, level:1, question:"What is the primary security risk associated with removable media in enterprise environments?", options:["A Removable media are slower than network transfers and introduce performance bottlenecks in sensitive data processing and collaboration workflows","B Removable media are expensive to manage at enterprise scale, creating inefficiencies compared to cloud storage services for data transfer needs","C Removable media can introduce malware into organizational systems and enable unauthorized data exfiltration that bypasses network-based security controls","D Removable media can physically damage computer ports and connectors when inserted incorrectly, causing expensive hardware repairs and downtime"], correct:2, explanation:"The primary security risks of removable media are malware introduction and data exfiltration. These bypass network controls. Physical damage, performance, and cost are not the security rationale for removable media policies." },
  { id:30155, domain:1, level:2, question:"What is the purpose of a security policy exception process?", options:["A An exception process creates a changelog for all policy revisions so auditors can verify that governance procedures align with regulatory requirements","B An exception process permanently removes security requirements for employees who find controls inconvenient, trading security for improved productivity","C An exception process identifies policy violations and initiates disciplinary procedures against employees who fail to comply with security requirements","D An exception process formally documents, risk-assesses, and time-bounds approved deviations from policy when business needs cannot be met within standard controls"], correct:3, explanation:"Exception processes formally document and govern legitimate deviations from policy. They're not permanent bypasses, disciplinary tools, or change management records—they are risk-managed approvals for specific situations." },
  { id:30156, domain:2, level:2, question:"What is 'data discovery' in the context of enterprise data security programs?", options:["A Data discovery tools analyze user behavior patterns to identify anomalous access activity that may indicate insider threats or compromised accounts","B Data discovery tools create encrypted backup copies of sensitive data to ensure quick recovery if primary storage systems experience failures or corruption","C Data discovery tools monitor network traffic in real time to identify unauthorized data transfers between internal systems and external destinations","D Data discovery tools scan storage repositories, endpoints, email systems, and cloud services to locate where sensitive data actually resides in the environment"], correct:3, explanation:"Data discovery tools find where sensitive data exists across the environment—essential for classification program implementation. Network monitoring (DLP), backup, and UEBA are separate technology categories." },
  { id:30157, domain:1, level:3, question:"What is 'risk tolerance' and how does it differ from 'risk appetite'?", options:["A Risk tolerance and risk appetite are identical terms used interchangeably in risk management frameworks to describe acceptable risk levels","B Risk appetite is the broad level of risk the organization accepts in pursuing objectives; risk tolerance is the acceptable variance or deviation around the risk appetite","C Risk appetite is set by external regulators; risk tolerance is determined internally by executive management based on business strategy and objectives","D Risk tolerance applies only to financial and operational risks; risk appetite is a broader concept covering compliance and reputational risk categories"], correct:1, explanation:"Risk appetite is the overall risk stance. Risk tolerance is the acceptable deviation around that appetite. They are related but distinct concepts used together in enterprise risk management frameworks." },
  { id:30158, domain:2, level:3, question:"What is the primary distinction between a data 'controller' and data 'processor' under GDPR?", options:["A A data controller determines the purposes and means of processing personal data; a data processor processes data on behalf of and under instructions from the controller","B A data controller always owns the data it processes; a data processor always receives data from a third-party source before beginning any processing","C A data controller handles structured database records; a data processor handles unstructured data like documents, emails, and multimedia content only","D A data controller is a technical system that processes personal data; a data processor is the human operator who manages and monitors that system"], correct:0, explanation:"GDPR: controllers determine why and how data is processed; processors act on controller instructions. Both can be organizations or individuals. Cloud providers are often processors but context determines the role." },
  { id:30159, domain:1, level:1, question:"What is the primary purpose of security governance in an organization?", options:["A Security governance focuses on securing the network perimeter using firewalls, DMZ architecture, and intrusion prevention system deployments","B Security governance oversees the daily technical operations of security tools including SIEM dashboards, firewalls, and endpoint protection platforms","C Security governance manages vendor contracts and ensures third-party security services meet the technical requirements specified in service agreements","D Security governance provides strategic direction, accountability, and oversight for the security program aligned with business strategy and objectives"], correct:3, explanation:"Security governance provides strategic direction and accountability aligned with organizational goals. Daily operations, perimeter security, and vendor management are tactical activities that operate under the governance framework." },
  { id:30160, domain:2, level:1, question:"What is the purpose of 'chain of custody' documentation in data security and forensics?", options:["A Chain of custody describes the hierarchy of classification authority from executives through managers to individual data owners in the organization","B Chain of custody is the organizational process of transferring data ownership and responsibilities when employees leave or change roles within a company","C Chain of custody documents the chronological record of who handled evidence or sensitive assets and when, maintaining integrity for legal and audit purposes","D Chain of custody refers to the procurement supply chain process for acquiring and receiving technology hardware and software for organizational use"], correct:2, explanation:"Chain of custody documents handling history of evidence or sensitive assets to maintain integrity for legal proceedings and audits. It's not procurement, employee offboarding, or a classification hierarchy." },
  { id:30161, domain:1, level:2, question:"What is a Privacy Impact Assessment (PIA) and when should one be conducted?", options:["A A PIA is a technical vulnerability scan that checks systems for misconfigurations that could expose personal information to unauthorized external access","B A PIA systematically evaluates how a project or system collects, uses, shares, and protects PII to identify privacy risks and required mitigation measures","C A PIA is an annual regulatory submission required by GDPR documenting all personal data processing activities conducted by the organization globally","D A PIA is a legal document signed by employees acknowledging they have read and understood the organization's data privacy and handling policies"], correct:1, explanation:"A PIA (DPIA in GDPR) systematically evaluates privacy risks in systems or projects. It's a risk assessment process, not a technical scan, employee acknowledgment, or annual regulatory filing." },
  { id:30162, domain:2, level:2, question:"What distinguishes physical data destruction from logical/software data destruction methods?", options:["A Physical destruction is required by law for all sensitive data disposal; logical methods are only permitted for non-sensitive data classification levels","B Physical destruction uses overwriting algorithms that require specialized hardware; logical destruction uses standard operating system tools available to any user","C Physical destruction permanently and irreversibly destroys the storage media itself; logical destruction attempts to erase data while leaving the media intact","D Physical destruction applies only to magnetic hard drives; logical destruction applies to SSDs, flash drives, and all non-magnetic storage media types"], correct:2, explanation:"Physical destruction destroys the media irreversibly (shredding, incineration). Logical methods (overwriting, crypto-shredding) erase data but leave media intact. Both can apply to various media types. Legal requirements vary by context." },
  { id:30163, domain:1, level:3, question:"In a BIA, what does Maximum Tolerable Downtime (MTD) represent?", options:["A MTD is the longest period a critical business function can be unavailable before causing irreversible harm to the organization or violating legal obligations","B MTD is the target time within which a business function must be restored to avoid significant financial losses; it equals the Recovery Time Objective","C MTD is the maximum acceptable amount of data loss measured in time, indicating how old a backup can be when used for restoration purposes","D MTD is the average time required to repair a failed system component and restore normal operations based on historical incident data analysis"], correct:0, explanation:"MTD (Maximum Tolerable Downtime) defines the survival limit—the longest a function can be unavailable before causing irreversible harm. RTO must be less than MTD. RPO is about data loss. MTTR is an availability metric." },
  { id:30164, domain:2, level:3, question:"What is 'information lifecycle management' (ILM) and its relationship to compliance?", options:["A ILM manages data from creation through destruction, ensuring appropriate security controls, retention policies, and compliance requirements are applied at every stage","B ILM is primarily a cost optimization strategy for tiering data to cheaper storage as it ages, with compliance being an incidental secondary benefit","C ILM focuses exclusively on archiving requirements and does not address the creation, active use, sharing, or final destruction phases of the data lifecycle","D ILM is a proprietary storage vendor framework used to optimize infrastructure investments and is unrelated to security or compliance requirements"], correct:0, explanation:"ILM governs the entire data lifecycle—creation, use, archiving, and destruction—ensuring security and compliance at each phase. It's not just cost optimization or archiving; it's a comprehensive governance framework." },
  { id:30165, domain:1, level:1, question:"What is the primary purpose of separation of duties in security governance?", options:["A Separation of duties prevents fraud and errors by requiring multiple individuals to complete critical transactions, so no single person has end-to-end control","B Separation of duties ensures different departments report to different executives, preventing organizational conflicts of interest in technology decisions","C Separation of duties requires different security tools to be managed by separate vendors, preventing excessive vendor control over security infrastructure","D Separation of duties improves operational efficiency by ensuring employees specialize in individual tasks and don't need to learn multiple processes"], correct:0, explanation:"SoD prevents single-person fraud and error by requiring multiple parties to complete critical processes. It's an internal control principle, not an efficiency measure, org-chart design, or vendor diversification strategy." },
  { id:30166, domain:2, level:1, question:"What does 'data classification' help organizations achieve in their security programs?", options:["A Data classification organizes data into categories based on sensitivity and value so that appropriate security controls and handling requirements can be applied","B Data classification identifies employees authorized to access specific systems by mapping their job roles to application entitlements in directory services","C Data classification assigns monetary value to all data assets so the finance team can report intellectual property on the organization's balance sheets","D Data classification creates a comprehensive hardware and software asset inventory so IT can track lifecycle management and maintenance requirements"], correct:0, explanation:"Data classification enables appropriate security controls by categorizing data by sensitivity. Asset valuation, access management, and hardware inventory are related but separate programs." },
  { id:30167, domain:1, level:2, question:"What is the primary purpose of security metrics in governance programs?", options:["A Security metrics are technical measurements from security tools reviewed only by the SOC team for daily operational awareness and incident triage","B Security metrics are collected primarily to satisfy auditors that security controls are operating, providing compliance documentation for regulatory review","C Security metrics provide measurable data to demonstrate program effectiveness, support decision-making, and track progress against defined security objectives","D Security metrics calculate the precise financial loss from every security incident so the organization can accurately report security costs to finance teams"], correct:2, explanation:"Security metrics enable measurement of effectiveness, inform decisions, and track progress. Financial loss calculation and compliance documentation are specific uses. SOC metrics are operational; governance metrics inform strategic decisions." },
  { id:30168, domain:2, level:2, question:"What is 'data portability' under GDPR and how does it benefit data subjects?", options:["A Data portability is a backup requirement mandating that organizations store data copies in multiple geographic locations for redundancy and disaster recovery","B Data portability requires organizations to encrypt data so it can be safely transferred between cloud providers without exposing personal data to interception","C Data portability is the right of individuals to receive their personal data in a structured, machine-readable format and transfer it to another service provider","D Data portability refers to technical standards for encoding data so it can be read across different operating systems and application platforms uniformly"], correct:2, explanation:"GDPR Article 20 grants individuals the right to receive their data in a portable format and transfer it to another controller. It empowers data subjects, not organizations, and is a privacy right rather than a technical standard." },
  { id:30169, domain:1, level:3, question:"What distinguishes 'inherent risk' from 'residual risk' in risk management?", options:["A Inherent risk applies only to physical threats like natural disasters; residual risk applies to cyber threats after technical security controls are deployed","B Inherent risk is the risk that has been transferred to insurers; residual risk is the risk that management has formally accepted and documented in the risk register","C Inherent risk is the risk remaining after controls are applied; residual risk is the initial risk level before any security controls are considered or implemented","D Inherent risk is the level of risk before any controls are applied; residual risk is what remains after controls are implemented and management decides to accept"], correct:3, explanation:"Inherent risk exists before controls. Residual risk is what remains after controls. These are foundational risk management concepts. They apply to all risk types, not just physical or cyber." },
  { id:30170, domain:2, level:3, question:"What security measures should organizations contractually require from cloud providers when storing classified data?", options:["A Indemnification clauses making providers fully financially liable for all costs associated with any breach or unauthorized disclosure of customer data","B A 99.99% uptime SLA ensuring classified data remains accessible to authorized users at all times without service interruptions or maintenance windows","C Data processing agreements specifying data location restrictions, security control requirements, breach notification timelines, and customer audit rights","D Non-disclosure agreements preventing cloud providers from acknowledging the organization's existence as a customer to any external parties"], correct:2, explanation:"Data processing agreements (DPAs) are the critical contractual requirement—covering data location, security requirements, breach notification, and audit rights. SLAs, NDAs, and indemnification are important supplements but secondary to comprehensive DPAs." },
  { id:30171, domain:1, level:1, question:"What is the primary purpose of a Disaster Recovery Plan (DRP)?", options:["A To document all potential disasters and assess their likelihood and business impact as part of the organization's risk assessment process","B To restore IT systems, applications, and data to operational status as quickly as possible following a disruptive incident, disaster, or major outage","C To provide guidance on physical security responses during natural disasters including evacuation procedures and employee physical safety protocols","D To ensure critical business functions continue operating during a disaster by activating alternate work sites and manual fallback business processes"], correct:1, explanation:"DRP focuses on restoring IT systems and data. BCP ensures business functions continue. Physical evacuation is emergency management. Risk assessment of disaster scenarios is part of BIA, not DRP execution." },
  { id:30172, domain:2, level:1, question:"What is the key difference between 'need-to-know' and 'least privilege'?", options:["A Need-to-know restricts information access based on specific job requirements; least privilege restricts system permissions to the minimum needed for tasks","B Need-to-know applies only to classified government programs; least privilege is a commercial concept used exclusively in private sector IT environments","C Need-to-know applies to stored data only; least privilege governs permissions for data in transit and active processing in network applications","D Need-to-know is technically enforced by ACLs and permissions; least privilege is enforced only through administrative approval procedures and policies"], correct:0, explanation:"Need-to-know governs access to information based on job-specific requirements. Least privilege governs system permissions and capabilities. Both apply broadly across government and commercial environments." },
  { id:30173, domain:1, level:2, question:"What is the NIST Cybersecurity Framework's primary structure?", options:["A The NIST CSF is organized around three tiers—Partial, Risk Informed, and Adaptive—that describe organizational cybersecurity maturity levels","B The NIST CSF has five core functions—Identify, Protect, Detect, Respond, and Recover—organized into categories and subcategories of security outcomes","C The NIST CSF organizes security into four domains—Governance, Operations, Technology, and Assurance—each with specific control requirements","D The NIST CSF is structured around 18 control families covering all aspects of security from access control to system integrity and supply chain management"], correct:1, explanation:"The NIST CSF core consists of five functions: Identify, Protect, Detect, Respond, Recover. The three Tiers describe maturity. Control families are from NIST SP 800-53. The four-domain structure describes other frameworks." },
  { id:30174, domain:2, level:2, question:"What is 'pseudonymization' and how does it reduce privacy risk while preserving data utility?", options:["A Pseudonymization replaces direct identifiers with artificial codes, reducing privacy risk while allowing data to still be used for analysis with the key held separately","B Pseudonymization applies encryption to entire database records, preventing unauthorized users from reading any fields while maintaining data availability for authorized access","C Pseudonymization creates synthetic data that statistically mirrors real data but contains no actual personal information, suitable for all analytics use cases","D Pseudonymization permanently removes all identifying information from datasets, making re-identification impossible and removing data from GDPR scope entirely"], correct:0, explanation:"Pseudonymization replaces identifiers with codes, reducing re-identification risk while preserving analytical utility. Unlike anonymization, it's reversible and data remains personal data under GDPR. It differs from encryption or synthetic data." },
  { id:30175, domain:1, level:3, question:"What should happen to identified risks that exceed an organization's risk tolerance?", options:["A Risks exceeding tolerance must be treated—mitigated, transferred, avoided, or managed—until residual risk falls within acceptable tolerance boundaries","B Risks exceeding tolerance should be automatically accepted and documented in the risk register without further analysis or management action","C Risks exceeding tolerance should be classified as critical assets and reported directly to regulators before any internal treatment actions are taken","D Risks exceeding tolerance should be transferred to insurance carriers immediately, regardless of whether more cost-effective treatment options exist"], correct:0, explanation:"Risks exceeding tolerance require treatment (mitigation, transfer, or avoidance) until residual risk is within tolerance. Automatic acceptance, immediate insurance transfer without analysis, and mandatory regulatory reporting are not standard responses." },
  { id:30176, domain:2, level:3, question:"What specific security risk do 'inference attacks' pose in classified database systems?", options:["A Inference attacks use SQL injection vulnerabilities to execute unauthorized queries and extract entire tables of sensitive data in a single operation","B Inference attacks allow users to deduce the values of data they lack authorization to view directly by analyzing patterns in permitted query results","C Inference attacks exploit poorly configured access controls that allow lower-privileged users to escalate permissions to higher classification levels","D Inference attacks install keyloggers on database administrator workstations to capture credentials and enable direct unauthorized database access"], correct:1, explanation:"Inference attacks allow users to deduce restricted data by analyzing permitted query results—a database security threat related to but distinct from aggregation. SQL injection, privilege escalation, and keylogging are different attack types." },
  { id:30177, domain:1, level:1, question:"What is 'availability' in the CIA triad?", options:["A Availability ensures that all user actions can be traced to specific individuals through comprehensive audit logging and non-repudiation mechanisms","B Availability ensures that information is only disclosed to authorized individuals and is not accessible to unauthorized parties or external adversaries","C Availability ensures that data remains accurate, complete, and unmodified during storage, processing, and transmission across all organizational systems","D Availability ensures that information and systems are accessible and usable by authorized users whenever they have a legitimate business need"], correct:3, explanation:"Availability ensures authorized users can access systems and data when needed. Confidentiality (A) prevents unauthorized disclosure. Integrity (B) protects accuracy. Accountability (D) is non-repudiation, not a CIA triad element." },
  { id:30178, domain:2, level:1, question:"Which classification label is most appropriate for public-facing marketing materials on a company website?", options:["A Restricted, because marketing materials may contain trademarked content that requires legal protection against unauthorized copying or reproduction","B Internal Use Only, because marketing materials contain strategic information about products and services that should be restricted to employees only","C Confidential, because all information created by the organization represents intellectual property that must be protected from competitor access","D Public, because the material is intentionally intended for public distribution and does not require restricted handling or access controls"], correct:3, explanation:"Public classification applies to information intentionally released for public consumption. Marketing website content is designed for public distribution. Confidential or Restricted would apply to sensitive internal information." },
  { id:30179, domain:1, level:2, question:"What is the primary purpose of personnel security controls such as background investigations?", options:["A To reduce the risk of insider threats by verifying the trustworthiness and character of individuals before granting them access to sensitive assets","B To comply with industry regulations requiring documented hiring history for all personnel who handle sensitive information and classified systems","C To create legal documentation protecting the organization from liability if an employee commits fraud or misconduct after being hired into a trusted role","D To identify employees who previously worked for competitors, enabling the organization to restrict their access to competitively sensitive information"], correct:0, explanation:"Background investigations reduce insider threat risk by verifying trustworthiness before granting access. Compliance documentation and legal protection are secondary benefits. Competitor screening is not a primary stated security purpose." },
  { id:30180, domain:2, level:2, question:"What is 'data sovereignty' and what risk does it create for cloud-hosted data?", options:["A Data sovereignty means the organization that creates data owns it exclusively, creating risk when cloud providers claim joint ownership through terms of service","B Data sovereignty means data encrypted at rest is exempt from disclosure requirements, creating risk that organizations may over-rely on encryption for compliance","C Data sovereignty subjects data to the laws of the country where it is stored, creating risk that foreign governments may compel disclosure or that conflicting legal requirements apply","D Data sovereignty means sensitive data must stay within company-owned infrastructure, making all cloud storage legally prohibited for regulated industries"], correct:2, explanation:"Data sovereignty subjects data to national law where it physically resides. This creates risk of government-compelled disclosure and conflicting legal requirements (e.g., US CLOUD Act vs. GDPR). It doesn't prohibit cloud use." },
  { id:30181, domain:1, level:3, question:"When conducting a threat model using STRIDE, which category addresses an attacker denying they performed a malicious action?", options:["A Tampering, which involves maliciously modifying data, software, or hardware to corrupt system functionality or integrity of processed information","B Spoofing, which involves impersonating another identity to gain unauthorized access to systems, data, services, or communication channels","C Repudiation, which involves denying that an action was performed, making it difficult to hold perpetrators accountable for malicious or unauthorized acts","D Denial of Service, which involves making systems or services unavailable to legitimate users by overwhelming resources or exploiting vulnerabilities"], correct:2, explanation:"Repudiation in STRIDE addresses denying actions were taken. Non-repudiation controls (audit logs, digital signatures) counter this. Spoofing is identity fraud. Tampering is data modification. DoS is availability attack." },
  { id:30182, domain:2, level:3, question:"What are the key security considerations when implementing a data classification program in an organization?", options:["A The primary consideration is regulatory compliance; all classification levels must directly map to specific regulations without additional organizational customization","B The only consideration is technology; organizations should choose DLP and encryption tools before defining classification levels and handling procedures","C The primary considerations are cost and performance impact; classification systems should be chosen based on minimal overhead to daily business operations","D Key considerations include defining classification levels, assigning ownership, establishing handling requirements, training staff, and enforcing controls at each level"], correct:3, explanation:"A comprehensive classification program requires: defined levels aligned with sensitivity, assigned owners, established handling requirements, staff training, and enforced technical/administrative controls. It's not primarily about cost, direct regulatory mapping, or technology-first approaches." },
  { id:30183, domain:1, level:1, question:"What is the relationship between a security standard and a security policy?", options:["A A policy states high-level mandatory organizational goals and requirements; a standard provides specific mandatory requirements that operationalize the policy","B A standard is developed by external regulatory bodies and must be adopted as-is; a policy is an internal document developed by the organization itself","C A standard applies only to technical security configurations; a policy applies to all aspects of the organization including people, process, and technology","D A standard is optional guidance that security staff may choose to follow; a policy is a mandatory directive that all organizational employees must comply with"], correct:0, explanation:"Policies state high-level goals; standards provide specific mandatory requirements supporting those goals. Both are mandatory. Standards can be internal or external. Both policies and standards apply broadly to people, process, and technology." },
  { id:30184, domain:2, level:1, question:"What is 'data in use' and what security challenge does it present?", options:["A Data in use is data stored in a database that is currently being read by an authorized user; the challenge is preventing concurrent unauthorized access","B Data in use is archived historical data accessed during audit processes; the challenge is maintaining its integrity and preventing unauthorized modification","C Data in use is backup data actively being transferred to offsite storage systems; the challenge is ensuring encryption during the transfer process","D Data in use is data actively being processed in memory or by applications, presenting security challenges because it is often in plaintext and harder to protect"], correct:3, explanation:"Data in use is actively being processed—often in plaintext in memory—making it harder to protect than data at rest or in transit. Memory scraping attacks and trusted execution environments address this specific challenge." },
  { id:30185, domain:1, level:2, question:"What is an Acceptable Use Policy (AUP) and what security purpose does it serve?", options:["A An AUP establishes rules for appropriate use of organizational IT resources, defining permitted activities, prohibited behaviors, and user responsibilities","B An AUP provides technical procedures for securely disposing of electronic media containing sensitive or proprietary organizational information","C An AUP specifies which employees are authorized to access sensitive data systems based on their job classification and documented business justification","D An AUP defines the minimum technical security configuration for organizational systems, specifying required settings for all managed endpoints and servers"], correct:0, explanation:"An AUP defines acceptable use of IT resources—permitted activities, prohibited behaviors, and consequences—serving as an administrative control governing employee behavior and establishing accountability." },
  { id:30186, domain:2, level:2, question:"What is the purpose of 'data quality' controls in an asset security program?", options:["A Data quality controls enforce encryption and access management standards across all systems handling data classified above the public level","B Data quality controls ensure data is accurate, complete, timely, and consistent, supporting its integrity and reliability for business and security decisions","C Data quality controls detect and prevent unauthorized access to sensitive data by monitoring for anomalous query patterns and access behaviors","D Data quality controls ensure data is regularly backed up and can be restored within defined recovery objectives, protecting business continuity"], correct:1, explanation:"Data quality ensures accuracy, completeness, consistency, and timeliness—supporting integrity. Backup/recovery, unauthorized access detection, and encryption enforcement are separate security control categories." },
  { id:30187, domain:1, level:3, question:"What is a 'security program charter' and why is it important for governance?", options:["A A security program charter is a memorandum of understanding signed with regulators specifying the security standards the organization commits to meeting","B A security program charter is the annual security budget document that defines financial resources and headcount allocated to the security function","C A security program charter is a service-level agreement with managed security providers defining response times and deliverable requirements for outsourced services","D A security program charter formally authorizes the security program, defines its scope, authority, mission, and accountabilities, giving it organizational legitimacy"], correct:3, explanation:"A security charter establishes the program's formal authority, scope, mission, and accountability structures within the organization. Without it, the security function lacks formal organizational standing." },
  { id:30188, domain:2, level:3, question:"What factors should drive an organization's decision on appropriate data destruction methods?", options:["A The primary factor is media format; organizations should apply identical destruction methods to all media types to simplify policy and reduce complexity","B The primary factor is cost; organizations should always use the least expensive destruction method available unless specifically required by regulation","C The data's classification level, applicable legal/regulatory requirements, media type, whether encryption was applied, and cost-effectiveness of available methods","D The primary factor is the age of the storage media; older media requires physical destruction while newer media can be reliably sanitized using software"], correct:2, explanation:"Appropriate destruction depends on multiple factors: classification level, legal requirements, media type (SSDs vs. HDDs), pre-existing encryption, and cost-effectiveness. No single factor—age, cost, or media format—drives the decision alone." },
  { id:30189, domain:1, level:1, question:"Which NIST document provides the comprehensive security and privacy control catalog for federal systems?", options:["A NIST SP 800-61 provides guidance on computer security incident handling and building effective incident response capabilities","B NIST SP 800-53 provides the comprehensive catalog of security and privacy controls for federal information systems and organizations","C NIST SP 800-30 provides guidance specifically for conducting risk assessments of federal information systems and their environments","D NIST SP 800-37 provides the Risk Management Framework guiding organizations through selecting, implementing, and authorizing security controls"], correct:1, explanation:"NIST SP 800-53 is the security and privacy control catalog. SP 800-37 is the RMF. SP 800-30 covers risk assessments. SP 800-61 covers incident handling." },
  { id:30190, domain:2, level:1, question:"What is the 'right to erasure' under GDPR, and what are its limitations?", options:["A The right to erasure requires anonymizing data rather than deleting it because complete deletion is technically impossible across distributed systems","B The right to erasure allows individuals to request deletion of their data, but organizations may decline when legal, public interest, or other lawful grounds apply","C The right to erasure applies only to data originally collected without valid consent; data collected lawfully cannot be deleted upon individual request","D The right to erasure requires immediate deletion of all personal data upon any request with no legal basis for refusal under any circumstances"], correct:1, explanation:"GDPR Article 17 provides the right to erasure with exceptions—organizations may refuse when processing is necessary for legal obligations, public interest, freedom of expression, or legal claims. It applies regardless of original collection basis." },
  { id:30191, domain:1, level:2, question:"What is the primary purpose of a security baseline?", options:["A A security baseline defines the minimum acceptable security configuration standard, providing a consistent, auditable starting point for system hardening","B A security baseline records the results of penetration tests to establish current security posture before remediation efforts begin and progress is tracked","C A security baseline is a threat intelligence report documenting the baseline level of attacks observed in the industry during a reference time period","D A security baseline documents the maximum allowed security configuration for systems to prevent over-engineering that could disrupt business operations"], correct:0, explanation:"Security baselines define minimum acceptable configurations (e.g., CIS benchmarks). They're starting points for consistent hardening across systems. They are not maximum limits, pen test records, or threat intelligence." },
  { id:30192, domain:2, level:2, question:"How does 'scoping' differ from 'tailoring' when applying security control baselines?", options:["A Scoping adds additional controls beyond the baseline while tailoring removes controls; together they adjust the baseline up or down based on system risk","B Scoping identifies which baseline controls are applicable to a specific system; tailoring adjusts selected controls through modifications, compensating controls, or supplements","C Scoping is performed by regulators to create industry-specific control requirements; tailoring is performed internally to adapt regulatory requirements to the organization","D Scoping and tailoring are identical processes; both terms describe selecting the applicable subset of controls from a baseline for a specific system"], correct:1, explanation:"Scoping selects applicable controls from the baseline. Tailoring adjusts those selected controls to fit the specific operational context (compensating controls, parameter modifications). They are sequential, complementary steps." },
  { id:30193, domain:1, level:3, question:"What is 'job rotation' and how does it complement separation of duties as a fraud prevention control?", options:["A Job rotation trains employees in multiple roles, creating workforce flexibility and ensuring no single-point-of-failure exists for critical operational knowledge","B Job rotation is a compliance tool that systematically moves employees between positions to meet regulatory requirements for segregated roles","C Job rotation is equivalent to mandatory vacation; both controls serve the identical purpose of temporarily removing employees from their roles to allow audits","D Job rotation moves employees through different roles over time, exposing irregularities a predecessor may have concealed while also reducing fraud opportunity through uncertainty"], correct:3, explanation:"Job rotation exposes irregularities by placing new eyes on a role, and also deters fraud because perpetrators know successors will review their work. It complements SoD (concurrent) with temporal control. It's related to but distinct from mandatory vacation." },
  { id:30194, domain:2, level:3, question:"What is the primary information security concern with 'data aggregation' attacks in multi-level security database systems?", options:["A Aggregation attacks combine individually authorized query results to infer sensitive information that exceeds the user's authorized access level","B Aggregation attacks overwhelm database query processors with simultaneous requests, causing denial of service to legitimate users needing system access","C Aggregation attacks exploit injection vulnerabilities to extract entire data tables in a single unauthorized transaction bypassing normal access controls","D Aggregation attacks use machine learning to automatically reclassify unclassified data and escalate its sensitivity level without administrative authorization"], correct:0, explanation:"Aggregation attacks combine individually permitted query results to infer restricted information—the core multi-level security concern. DoS, SQL injection, and automated reclassification are separate threat categories." },
  { id:30195, domain:1, level:1, question:"What is 'integrity' in the CIA triad?", options:["A Integrity ensures that only authorized users can access sensitive information and that all unauthorized access attempts are blocked and logged","B Integrity ensures that all user actions are traceable to specific individuals through comprehensive audit trail logging and digital signature mechanisms","C Integrity ensures that information and systems remain accessible and operational for authorized users whenever they have a legitimate business need","D Integrity ensures that data is accurate, complete, and has not been improperly modified during storage, processing, or transmission across systems"], correct:3, explanation:"Integrity ensures data accuracy and prevents unauthorized modification. Confidentiality (A) controls access. Availability (B) ensures access. Accountability/non-repudiation (D) provides traceability—important but not a CIA triad element." },
  { id:30196, domain:2, level:1, question:"What is the primary purpose of a data loss prevention (DLP) policy?", options:["A A DLP policy defines backup frequency and recovery procedures to ensure critical data can be restored within defined recovery time objectives","B A DLP policy defines the encryption standards that must be applied to all sensitive data both at rest and in transit across organizational systems","C A DLP policy establishes rules and controls governing how sensitive data may be used, shared, and transmitted to prevent unauthorized disclosure","D A DLP policy specifies technical architecture for network monitoring tools deployed to inspect traffic and identify suspicious data transfer patterns"], correct:2, explanation:"A DLP policy establishes rules and controls for preventing unauthorized disclosure of sensitive data. Backup procedures, network monitoring architecture, and encryption standards are governed by separate policy instruments." },
  { id:30197, domain:1, level:2, question:"What role does the 'authorizing official' play in the NIST Risk Management Framework?", options:["A The authorizing official monitors security controls on an ongoing basis and reports their operational status to the system owner and risk executive","B The authorizing official is a senior executive who reviews the security authorization package and makes a risk-based decision to grant or deny authority to operate","C The authorizing official assesses the effectiveness of implemented controls and produces the security assessment report used to support authorization decisions","D The authorizing official selects security controls from NIST SP 800-53 and documents them in the system security plan for implementation by IT teams"], correct:1, explanation:"The Authorizing Official (AO) is a senior executive who reviews the authorization package (SAR, POA&M, SSP) and makes the formal risk acceptance decision—granting or denying Authority to Operate (ATO)." },
  { id:30198, domain:2, level:2, question:"What is the key privacy protection challenge with 'big data' analytics environments?", options:["A Big data systems are technically incompatible with encryption, making it impossible to apply standard data-at-rest protection to personal information","B Big data analytics enable combining large volumes of diverse data to identify individuals or infer sensitive attributes from seemingly non-sensitive inputs","C Big data environments require extremely expensive storage infrastructure, making privacy-compliant retention policies economically difficult to implement","D Big data environments always violate data minimization principles because they intentionally collect as much data as possible for analytical purposes"], correct:1, explanation:"Big data analytics can re-identify individuals or infer sensitive attributes by combining diverse data—a fundamental privacy challenge. Cost, encryption incompatibility, and automatic minimization violations are not accurate characterizations." },
  { id:30199, domain:1, level:3, question:"A security professional discovers evidence that a colleague is misusing privileged access to steal customer data. What does the ISC² Code of Ethics require?", options:["A Report the issue only to direct management and take no further action, since the security professional's obligation to the employer supersedes other duties","B Keep the discovery confidential to avoid damaging the colleague's career and the organization's reputation while implementing compensating technical controls","C Act honorably by reporting the misconduct through appropriate internal and external channels, prioritizing protection of society over loyalty to colleagues","D Document the concern in the risk register as a potential insider threat and wait 90 days for management to respond before escalating further"], correct:2, explanation:"The ISC² Code of Ethics requires acting honorably and protecting society—its highest canon. The professional must report through appropriate channels (internal escalation, potentially law enforcement). Protecting colleagues, staying silent, or only doing technical fixes violates professional ethics." },
  { id:30200, domain:2, level:3, question:"What is the most comprehensive approach to protecting sensitive data throughout its entire lifecycle in a large enterprise?", options:["A Conduct annual security audits and penetration tests to identify data protection gaps and remediate findings before the next assessment cycle begins","B Deploy full-disk encryption on all endpoints and TLS on all network connections, protecting data at rest and in transit but not necessarily in use","C Implement strong network perimeter controls including next-generation firewalls and IPS systems to prevent unauthorized external access to all internal data","D Develop an integrated data governance framework combining classification, handling requirements, access controls, DLP, encryption, and secure destruction across all lifecycle phases"], correct:3, explanation:"A comprehensive data governance framework integrating classification, handling requirements, access controls, DLP, encryption, and lifecycle-appropriate destruction is the most complete approach. Perimeter-only, encryption-only, and audit-only approaches are all partial solutions." },
  { id:30201, domain:1, level:1, question:"Which of the following BEST describes the difference between a threat and a vulnerability in risk management?", options:["A A threat is quantifiable; a vulnerability is qualitative","B A threat is a potential cause of an unwanted incident; a vulnerability is a weakness that can be exploited by a threat","C A threat is internal; a vulnerability is external","D A threat is a weakness; a vulnerability is an attacker"], correct:1, explanation:"In risk management, a threat is any potential event or actor that could cause harm (natural disaster, attacker, insider), while a vulnerability is a weakness in a system, process, or control that a threat can exploit — risk is the combination of threat likelihood and vulnerability impact." },
  { id:30202, domain:1, level:2, question:"Which risk treatment option involves purchasing insurance to compensate for potential loss from a security incident?", options:["A Risk acceptance","B Risk mitigation","C Risk transfer","D Risk avoidance"], correct:2, explanation:"Risk transfer shifts the financial consequences of risk to another party (insurance company, outsourcing partner) without eliminating the underlying risk — the organization pays premiums in exchange for compensation if the risk materializes." },
  { id:30203, domain:1, level:2, question:"Which of the following BEST describes the purpose of a 'Business Impact Analysis' (BIA)?", options:["A Identifying critical business functions and the maximum tolerable downtime and data loss for each","B Analyzing competitive business impacts of security incidents","C Analyzing the financial impact of implementing security controls","D A financial analysis of the business case for security investments"], correct:0, explanation:"A BIA identifies critical business processes, quantifies the impact of their disruption (financial, operational, reputational), and establishes Recovery Time Objectives (RTO) and Recovery Point Objectives (RPO) — foundational inputs to business continuity and disaster recovery planning." },
  { id:30204, domain:1, level:3, question:"An organization's security policy states that all terminated employees' access must be revoked within 2 hours. An insider threat incident reveals that a terminated employee retained access for 3 weeks. Which type of control failure does this represent?", options:["A Preventive control failure","B Corrective control failure","C Detective control failure","D Compensating control failure"], correct:0, explanation:"The policy requiring 2-hour access revocation is a preventive control — designed to prevent unauthorized access from terminated employees; failure to implement it represents a preventive control failure, allowing the threat to materialize rather than preventing it." },
  { id:30205, domain:1, level:1, question:"What is the PRIMARY purpose of security awareness training?", options:["A Reducing human-factor risks by ensuring employees understand threats, responsibilities, and how to behave securely","B Satisfying compliance requirements for training documentation","C Teaching employees technical security skills","D Training employees to detect all types of cyber attacks"], correct:0, explanation:"Security awareness training's primary purpose is reducing human-factor risk — phishing susceptibility, social engineering, accidental data exposure, poor password practices — by ensuring all employees understand the threats they face, their responsibilities, and how to make secure decisions in daily work." },
  { id:30206, domain:1, level:2, question:"Which of the following BEST describes 'due care' in the context of information security?", options:["A Conducting annual security assessments","B Taking reasonable precautions to protect organizational assets, doing what a prudent person would do under the circumstances","C Following all regulatory compliance requirements exactly","D Ensuring security controls are properly documented"], correct:1, explanation:"Due care requires taking reasonable, prudent steps to protect assets — implementing controls appropriate to identified risks, following industry standards, and demonstrating that the organization acted responsibly; failure to exercise due care can create legal liability for negligence." },
  { id:30207, domain:1, level:2, question:"An organization implements mandatory vacation policies for employees handling financial transactions. Which security principle does this MOST directly support?", options:["A Separation of duties","B Fraud detection through coverage requirement","C Least privilege","D Defense in depth"], correct:1, explanation:"Mandatory vacation (forced leave) policies require other employees to cover functions when the primary person is absent, allowing supervisors to review work patterns and detect ongoing fraud that a present employee could conceal; it specifically detects fraud schemes that require continuous maintenance." },
  { id:30208, domain:2, level:1, question:"Which data classification level MOST commonly requires the highest level of security controls, including need-to-know access and strict handling procedures?", options:["A Top Secret/Restricted","B Confidential","C Internal","D Public"], correct:0, explanation:"The highest classification level (Top Secret in government, Restricted or Highly Confidential in commercial) imposes the strictest controls: need-to-know access strictly enforced, specific handling and storage requirements, strict transmission controls, and mandatory destruction at end-of-life." },
  { id:30209, domain:2, level:2, question:"Which of the following roles is PRIMARILY responsible for determining the classification level of data and implementing appropriate controls?", options:["A Data owner","B Data user","C Security administrator","D Data custodian"], correct:0, explanation:"The data owner (typically a business manager or executive) is responsible for determining the value and appropriate classification of data and defining handling requirements; the data custodian (typically IT) implements the technical controls the owner specifies." },
  { id:30210, domain:2, level:2, question:"An organization is decommissioning hard drives containing confidential personnel records. Which data destruction method provides the HIGHEST assurance that data is unrecoverable?", options:["A Formatting the drives","B Overwriting with single-pass zeros","C Degaussing followed by physical destruction (shredding/disintegration)","D Encryption of the drives before disposal"], correct:2, explanation:"Physical destruction (shredding, disintegration, incineration) provides absolute assurance that data is unrecoverable — no forensic recovery technique can reconstruct data from physically destroyed media; degaussing first ensures magnetic data is erased before mechanical shredding." },
  { id:30211, domain:1, level:1, question:"Which of the following BEST describes the concept of 'separation of duties'?", options:["A Isolating security controls from business processes","B Separating development and production environments","C Requiring that no single person has complete control over a critical function, distributing tasks across multiple individuals","D Dividing security teams into specialized units"], correct:2, explanation:"Separation of duties prevents fraud and errors by requiring multiple people to complete sensitive transactions — one person cannot both initiate and approve a payment, or both develop and deploy code to production — making it necessary for multiple people to collude for abuse." },
  { id:30212, domain:1, level:3, question:"A Chief Information Security Officer (CISO) presents a risk assessment to the executive team showing that implementing a $2M security control reduces a risk with $500K expected annual loss. The executive team should:", options:["A Consider the full picture including regulatory requirements, reputation risk, and liability before deciding","B Implement the control immediately regardless of cost","C Reject the control because the cost exceeds the expected loss benefit","D Always defer to the CISO's recommendation on security investments"], correct:0, explanation:"The annualized loss expectancy ($500K) doesn't justify the $2M control cost purely economically, but risk decisions must consider factors beyond direct financial loss: regulatory fines that could exceed $2M, reputational damage, litigation costs, and strategic risk — the full risk picture should inform the decision." },
  { id:30213, domain:2, level:2, question:"Which of the following BEST describes the security concept of 'data remanence'?", options:["A Data that remains relevant beyond its intended retention period","B Backup data that remains accessible after the restoration deadline","C Data that persists in cloud storage after contract termination","D Residual data that remains on storage media after deletion attempts, potentially recoverable by specialized techniques"], correct:3, explanation:"Data remanence is the residual representation of data that remains on storage media even after deletion — magnetic force microscopy can recover overwritten data; flash storage wear leveling retains data in unused cells; DRAM retains data briefly after power loss — requiring appropriate sanitization methods based on media type." },
  { id:30214, domain:1, level:1, question:"Which of the following BEST describes the concept of 'non-repudiation' in information security?", options:["A The prevention of data modification by unauthorized parties","B The ability to prevent unauthorized access to systems","C The assurance that data is available to authorized users when needed","D The assurance that an action or communication cannot be denied by the party who performed it"], correct:3, explanation:"Non-repudiation provides proof that a specific entity performed a specific action — digital signatures bind an action cryptographically to an identity; audit logs with timestamps create non-repudiable records; preventing parties from falsely denying actions they took is critical for legal enforceability and accountability." },
  { id:30215, domain:1, level:2, question:"Which of the following is the MOST important factor in establishing an effective information security governance program?", options:["A Having a large security budget and advanced technology","B A large and well-trained security team","C Comprehensive technical security controls","D Executive management commitment and accountability for security risk"], correct:3, explanation:"Executive commitment is the foundational requirement for effective security governance — without it, security lacks authority, resources, and organizational standing; executives must own security risk, champion security culture, and ensure accountability, which drives all other program elements." },
  { id:30216, domain:2, level:1, question:"Which of the following BEST describes 'data retention policies' and their security significance?", options:["A Policies defining the maximum storage capacity for different data types","B Policies defining how long data must be kept and when it must be destroyed — balancing legal requirements, operational needs, and minimizing breach exposure","C Policies governing data backup frequency and media rotation","D Policies for classifying data by business value for retention prioritization"], correct:1, explanation:"Data retention policies balance competing requirements: legal minimums (some records must be retained for years), operational needs (access data while useful), and data minimization principles (destroy data when no longer needed to reduce breach impact and storage costs)." },
  { id:30217, domain:1, level:2, question:"An organization decides to outsource its payroll processing to a third-party service provider. From a security governance perspective, which responsibility CANNOT be outsourced?", options:["A Employee training delivery","B Technical security implementation","C Compliance with applicable regulations","D Day-to-day security monitoring"], correct:2, explanation:"Regulatory compliance responsibility remains with the organization regardless of outsourcing arrangements — the regulated entity cannot delegate compliance accountability to a service provider; the organization remains liable for regulatory violations even when a third party causes them." },
  { id:30218, domain:2, level:3, question:"A forensic investigation requires preserving evidence from a compromised server. The FIRST action the forensic investigator should take is:", options:["A Shut down the server to prevent further damage","B Document and photograph the system state, capturing volatile data (memory, running processes, network connections) before any other actions","C Run antivirus scans to identify the malware","D Restore the server from the most recent clean backup"], correct:1, explanation:"Forensic evidence collection follows the order of volatility — most volatile data (CPU registers, routing tables, ARP cache, running processes, memory) is captured first because it is lost when the system is powered down; documentation preserves the scene before anything is disturbed." },
  { id:30219, domain:1, level:1, question:"Which of the following is the BEST example of 'administrative controls' in information security?", options:["A Physical locks and badge readers","B Encryption and access control lists","C Firewalls and intrusion detection systems","D Security policies, procedures, and training programs"], correct:3, explanation:"Administrative controls (also called managerial or procedural controls) are policies, standards, procedures, training, background checks, and management oversight mechanisms — distinct from technical controls (firewalls, encryption) and physical controls (locks, CCTV)." },
  { id:30220, domain:1, level:2, question:"Which of the following BEST describes 'residual risk'?", options:["A Risk transferred to insurance companies","B Risk that remains after all possible security controls have been applied","C The risk remaining after risk treatment measures have been applied","D Risk that applies to legacy systems with no remediation options"], correct:2, explanation:"Residual risk is the risk that remains after applying security controls — no control eliminates risk entirely; after implementing countermeasures, the remaining risk must be explicitly accepted by management, with the acceptance documented as part of the risk management process." },
  { id:30221, domain:2, level:2, question:"Which principle of privacy protection requires that personal information be collected only to the extent necessary for the stated purpose?", options:["A Individual participation","B Purpose limitation","C Data accuracy","D Data minimization"], correct:3, explanation:"Data minimization (a GDPR and OECD privacy principle) requires collecting only the personal information that is adequate, relevant, and limited to what is necessary for the specified purpose — minimizing privacy risk by limiting data collection." },
  { id:30222, domain:1, level:1, question:"In the context of security governance, what is the PRIMARY role of the Board of Directors?", options:["A Implementing day-to-day security controls","B Conducting security audits and penetration tests","C Providing ultimate oversight and accountability for security risk as part of enterprise risk governance","D Managing the security operations center"], correct:2, explanation:"The board provides governance oversight — ensuring management has appropriate risk frameworks, that material security risks are identified and managed within acceptable levels, and that the organization meets its obligations; the board sets risk appetite and holds management accountable for security risk management." },
  { id:30223, domain:2, level:2, question:"Which data handling requirement MOST effectively prevents sensitive data from being included in application logs?", options:["A Restricting log access to security staff only","B Implementing output encoding for sensitive fields","C Encrypting all application logs","D Implementing data masking/scrubbing in logging frameworks to prevent sensitive data from being written to logs"], correct:3, explanation:"Log scrubbing/masking at the logging layer prevents sensitive data (credentials, PII, payment card numbers) from being written to logs in the first place — encryption protects logs at rest but doesn't prevent sensitive data from being stored in them, while masking eliminates the data before it reaches the log." },
  { id:30224, domain:1, level:3, question:"An organization's risk assessment identifies 50 security risks. Management asks for the MOST efficient approach to prioritizing remediation. The security team should:", options:["A Conduct qualitative risk analysis only to quickly categorize all risks","B Address all 50 risks with equal urgency","C Plot risks on a risk matrix by likelihood and impact, focusing first on high-likelihood/high-impact risks while accepting low-likelihood/low-impact risks","D Rank risks by likelihood only, remediating the most likely threats first"], correct:2, explanation:"A risk matrix (plotting likelihood against impact) enables efficient prioritization — high/high risks deserve immediate attention, high impact/low likelihood risks need contingency plans, and low/low risks may be accepted with minimal investment; this approach maximizes risk reduction per security dollar spent." },
  { id:30225, domain:1, level:2, question:"Which of the following BEST describes the 'annualized loss expectancy' (ALE) calculation?", options:["A ALE = Control Cost × Risk Reduction Percentage","B ALE = Single Loss Expectancy (SLE) × Annualized Rate of Occurrence (ARO)","C ALE = Asset Value × Exposure Factor","D ALE = Threat Likelihood × Vulnerability Severity"], correct:1, explanation:"ALE = SLE × ARO: the Single Loss Expectancy (asset value × exposure factor) represents the expected loss per incident, while the Annualized Rate of Occurrence represents how often the threat is expected to occur per year — ALE quantifies the expected annual financial loss from a specific threat." },
  { id:30226, domain:2, level:1, question:"Which of the following BEST describes the difference between data classification and data categorization?", options:["A They are identical concepts with different names","B Classification is technical; categorization is administrative","C Classification is for government data; categorization is for commercial data","D Classification assigns sensitivity labels based on confidentiality requirements; categorization groups data by type, function, or other organizational criteria"], correct:3, explanation:"Data classification assigns sensitivity levels (public, confidential, secret) based on confidentiality, integrity, and availability requirements; data categorization groups data by other criteria (financial data, PII, healthcare data) that may span multiple classification levels — both are part of comprehensive data governance." },
  { id:30227, domain:1, level:2, question:"Which security governance document defines the SPECIFIC technical requirements for implementing security policies?", options:["A Security policy","B Security guideline","C Security standard","D Security procedure"], correct:2, explanation:"Security standards define specific, mandatory technical requirements (e.g., 'all passwords must be at least 14 characters including uppercase, lowercase, numbers, and symbols') — more specific than policies (which state intent) but less detailed than procedures (which provide step-by-step instructions)." },
  { id:30228, domain:2, level:3, question:"An organization conducts a data audit and discovers that multiple departments are sharing a single service account for database access. This practice MOST directly violates which security principle?", options:["A Individual accountability","B Least privilege","C Separation of duties","D Defense in depth"], correct:0, explanation:"Shared accounts eliminate individual accountability — audit logs show 'service account' rather than the specific person who performed an action, making it impossible to determine who is responsible for specific data access or modifications, which is fundamental to security investigation and non-repudiation." },
  { id:30229, domain:1, level:1, question:"Which of the following is the MOST important consideration when selecting security controls?", options:["A The controls must be visible to employees","B The controls must use the latest technology","C The controls must be automated","D The controls must be cost-effective relative to the risk they mitigate"], correct:3, explanation:"Security controls must be cost-effective — the cost of implementing and maintaining a control should not exceed the risk reduction it provides (though non-financial factors like regulatory compliance and reputational risk also inform decisions); spending $1M to protect a $10K asset is rarely justified." },
  { id:30230, domain:2, level:2, question:"Which of the following privacy regulations grants EU residents the right to request deletion of their personal data?", options:["A HIPAA","B GDPR's 'right to erasure' (Article 17)","C SOX","D COPPA"], correct:1, explanation:"GDPR Article 17 grants EU data subjects the right to request deletion ('right to be forgotten') of their personal data when certain conditions are met — the data is no longer needed for its original purpose, consent is withdrawn, or processing is unlawful — requiring organizations to have deletion processes in place." },
  { id:30231, domain:1, level:2, question:"Which type of attack targets the weakest link in an organization's security — the human element — through deception rather than technical exploitation?", options:["A Social engineering","B Zero-day exploit","C Supply chain attack","D Advanced Persistent Threat"], correct:0, explanation:"Social engineering exploits human psychology — trust, authority, fear, urgency — to manipulate people into revealing information or performing actions that compromise security; it bypasses technical controls by targeting the human element, making security awareness training a critical countermeasure." },
  { id:30232, domain:2, level:1, question:"Which of the following BEST describes 'due diligence' in third-party risk management?", options:["A Requiring vendors to sign security agreements","B Investigating and verifying a vendor's security practices and controls before establishing a relationship","C Implementing the same security controls in vendor environments as your own","D Conducting annual audits of all vendor security programs"], correct:1, explanation:"Due diligence involves investigating and verifying — reviewing SOC 2 reports, conducting security assessments, checking references, evaluating breach history — before entering a vendor relationship; it's the research that enables informed decisions about whether to accept the risk of the relationship." },
  { id:30233, domain:1, level:3, question:"A security policy requires strong authentication for all remote access. The IT team implements SMS-based two-factor authentication. A security review later reveals that SIM swapping attacks can compromise SMS-based 2FA. This represents:", options:["A A compensating control that adequately satisfies the policy requirement","B A gap between policy intent and implementation — the policy's security objective is not achieved by the implemented control","C Acceptable residual risk since 2FA is implemented","D A policy violation requiring immediate remediation"], correct:1, explanation:"SMS-based 2FA is technically a second factor, but SIM swapping attacks mean it doesn't provide the security strength the policy intended; this gap between policy objective (strong authentication) and implementation effectiveness requires either policy clarification or implementation upgrade to phishing-resistant MFA." },
  { id:30234, domain:2, level:2, question:"Which standard provides a framework for information security management systems (ISMS)?", options:["A ISO/IEC 27001","B PCI DSS","C NIST SP 800-53","D COBIT"], correct:0, explanation:"ISO/IEC 27001 specifies requirements for establishing, implementing, maintaining, and continually improving an Information Security Management System — the international standard for ISMS that provides a systematic approach to managing sensitive information security risks." },
  { id:30235, domain:1, level:1, question:"What does the term 'confidentiality' mean in the CIA triad?", options:["A Information is accessible only to authorized parties","B Authorized users can access data when needed","C Data is accurate and unmodified","D Data is protected from unauthorized modification"], correct:0, explanation:"Confidentiality ensures that information is accessible only to those authorized to access it — preventing unauthorized disclosure through access controls, encryption, data classification, and need-to-know enforcement." },
  { id:30236, domain:2, level:2, question:"Which of the following BEST describes the concept of 'privacy by default'?", options:["A Systems and processes should default to the most privacy-protective settings without requiring users to take action to protect their privacy","B Automatic application of the most stringent privacy laws","C Privacy settings that cannot be changed by users","D Setting maximum data collection as the default setting"], correct:0, explanation:"Privacy by default (GDPR Article 25) means that only necessary personal data is collected, and the most privacy-protective settings are the default — users should not need to take action to protect their privacy; opting in to data sharing should be required rather than opting out." },
  { id:30237, domain:1, level:2, question:"Which of the following categories of controls is BEST described as 'deterrent'?", options:["A Warning banners notifying users they are being monitored","B Encryption protecting data confidentiality","C Access control lists restricting file permissions","D Firewall blocking unauthorized traffic"], correct:0, explanation:"Deterrent controls discourage potential attackers or policy violations by making consequences known or increasing perceived risk of detection — warning banners, visible security cameras, and audit notifications discourage misconduct without physically preventing it." },
  { id:30238, domain:2, level:1, question:"Which of the following BEST describes the 'asset valuation' process in risk management?", options:["A Conducting an annual inventory of all IT assets","B Assessing the market value of hardware assets for accounting purposes","C Determining the value of assets to the organization — including replacement cost, business impact of loss, and sensitivity of data — to prioritize protection efforts","D Purchasing cybersecurity insurance to cover asset replacement costs"], correct:2, explanation:"Asset valuation determines protection priority — a server hosting publicly available information has much lower security value than one processing payment card data; value encompasses replacement cost, revenue impact of unavailability, regulatory exposure if compromised, and competitive intelligence value to adversaries." },
  { id:30239, domain:1, level:3, question:"An organization's security team discovers that a critical security patch released two months ago has not been applied to 40% of servers because the change management process requires 90-day testing cycles. The MOST appropriate response is:", options:["A Document the risk and present it to leadership for risk acceptance or emergency patch authorization","B Implement compensating controls while following the expedited emergency change process for critical patches","C Override the change management process and immediately patch all servers","D Accept the risk for the remaining servers until the 90-day cycle completes"], correct:1, explanation:"Critical vulnerabilities require balancing patch urgency with stability requirements; the appropriate process is the emergency change process (which should exist for exactly this scenario) combined with compensating controls (network isolation, enhanced monitoring) while patches are tested on an expedited timeline — not overriding governance or indefinitely accepting high risk." },
  { id:30240, domain:2, level:2, question:"Which of the following BEST describes the security concept of 'information asset inventory'?", options:["A A database of all employee access rights","B A comprehensive catalog of information assets including their classification, location, owner, and protective requirements","C An inventory of all software licenses in the organization","D A list of all hardware assets in the organization"], correct:1, explanation:"An information asset inventory catalogs all information assets (databases, files, systems, intellectual property) with their classification level, business owner, physical/logical location, and required protections — providing the foundation for risk-based security program management and incident response." },
  { id:30241, domain:1, level:2, question:"What is the PRIMARY objective of a 'privacy impact assessment' (PIA)?", options:["A Systematically identifying and addressing privacy risks before implementing systems or processes that handle personal information","B Assessing privacy breaches after they occur to determine regulatory exposure","C Assessing the financial impact of privacy regulation compliance","D Measuring the performance of privacy controls after deployment"], correct:0, explanation:"A PIA (or DPIA under GDPR) proactively identifies privacy risks in proposed systems, processes, or data uses before deployment — evaluating necessity, proportionality, and risks to data subjects, then designing mitigations — preventing privacy problems from being built into systems." },
  { id:30242, domain:1, level:1, question:"Which of the following is the MOST effective method for ensuring that security policies are followed throughout an organization?", options:["A Publishing policies on the intranet for employees to read","B Imposing severe penalties for all policy violations","C Implementing technical controls that enforce policy compliance and conducting regular awareness training and audits","D Requiring annual policy sign-off from employees"], correct:2, explanation:"Effective policy implementation requires multiple complementary approaches: technical enforcement (automated controls that make compliance the default), training (ensuring employees understand), and auditing (verifying compliance and detecting violations) — passive publication or signature alone does not drive consistent compliance." },
  { id:30243, domain:2, level:3, question:"An organization is considering using a cloud provider to store regulated health information. The FIRST step in evaluating this option should be:", options:["A Migrating test data to evaluate the platform's performance","B Conducting a penetration test of the cloud provider","C Negotiating the service contract pricing","D Determining whether the cloud provider meets HIPAA technical safeguard requirements and will sign a Business Associate Agreement"], correct:3, explanation:"Regulatory compliance must be verified before storing PHI anywhere — the cloud provider must meet HIPAA technical safeguard requirements and be willing to enter a Business Associate Agreement accepting their security obligations; these are non-negotiable prerequisites before any other evaluation or data migration." },
  { id:30244, domain:1, level:2, question:"Which of the following types of law governs privacy rights and data protection obligations in the European Union?", options:["A Criminal law","B Civil law based on the GDPR framework","C Common law","D International treaty law"], correct:1, explanation:"EU privacy is governed by civil/administrative law — the GDPR is an EU Regulation (directly applicable in all member states) creating civil obligations; violations result in administrative fines rather than criminal prosecution in most cases, though some member states have criminal provisions for willful violations." },
  { id:30245, domain:2, level:2, question:"Which of the following BEST describes the security concept of 'data minimization' in the context of system design?", options:["A Collecting, processing, and retaining only the minimum data necessary to fulfill the specified purpose","B Minimizing the storage space used by data","C Compressing data to minimize transmission bandwidth","D Minimizing the number of users who have access to data"], correct:0, explanation:"Data minimization (a GDPR principle and privacy best practice) requires collecting only what is necessary — not collecting 'potentially useful' data; minimizing processing scope; and deleting data when it is no longer needed — reducing privacy risk, breach impact, and compliance burden." },
  { id:30246, domain:1, level:1, question:"In a well-designed security governance structure, who is ULTIMATELY accountable for information security within an organization?", options:["A The Chief Information Security Officer (CISO)","B Senior management and the Board of Directors","C The IT department","D The legal and compliance team"], correct:1, explanation:"Ultimate accountability for security risk rests with senior management and the board — they define risk appetite, ensure adequate resources, and are legally accountable to stakeholders; the CISO manages the security program on their behalf but cannot independently bear organizational accountability for security outcomes." },
  { id:30247, domain:2, level:2, question:"Which of the following is the MOST important consideration when defining data retention periods?", options:["A Technical capacity of backup systems","B Storage cost optimization","C User convenience and data accessibility","D Compliance with all applicable legal, regulatory, and contractual retention requirements while applying data minimization principles"], correct:3, explanation:"Retention periods must satisfy legal minimums (many regulations require specific retention periods), operational needs, and litigation hold requirements — while applying data minimization by not retaining data longer than necessary; violating minimum retention is a compliance violation, but excessive retention increases breach impact and privacy risk." },
  { id:30248, domain:1, level:3, question:"A CISSP is reviewing a proposed enterprise security architecture. The architecture includes a single, centralized security monitoring system with no redundancy. The MOST significant concern is:", options:["A Regulatory requirements mandate distributed monitoring","B The single system may be too expensive to maintain","C Centralization reduces security visibility","D The single system creates a single point of failure — if compromised by an attacker or fails during an incident, the organization loses security visibility at the most critical time"], correct:3, explanation:"Single points of failure in security infrastructure are especially dangerous — the security monitoring system is most critical during incidents; an attacker who can disable the SIEM or SOC can operate undetected; and infrastructure failures during incidents eliminate response capability when it's most needed." },
  { id:30249, domain:2, level:1, question:"Which of the following BEST describes 'chain of custody' in digital forensics?", options:["A The contractual chain connecting forensic service providers","B A documented record tracking who collected, handled, transferred, and analyzed evidence from collection to presentation in legal proceedings","C The technical process of preserving digital evidence","D The organizational hierarchy responsible for forensic investigations"], correct:1, explanation:"Chain of custody documents every person who handled evidence, when, why, and what was done with it — maintaining this unbroken record is essential for legal admissibility; gaps in chain of custody can cause evidence to be excluded, allowing guilty parties to escape accountability." },
  { id:30250, domain:1, level:2, question:"Which of the following BEST describes the role of 'ethics' in the information security profession?", options:["A Ethics are optional guidelines for security professionals","B Ethics are the same as legal requirements","C Ethics only apply when laws don't explicitly govern a situation","D Security professionals have special access to sensitive systems and information, creating ethical obligations to use this access appropriately, protect confidentiality, and act in the interest of the organization and society"], correct:3, explanation:"Security professionals' privileged access to systems, sensitive data, and network infrastructure creates significant ethical obligations beyond legal compliance — using access only for authorized purposes, protecting confidential information, maintaining professional competence, and acting in good faith when competing obligations arise are core professional ethics." },
  { id:30251, domain:3, level:1, question:"Which security model operates on the principle of 'no read up, no write down' to enforce confidentiality in multilevel secure systems?", options:["A Clark-Wilson model","B Biba model","C Bell-LaPadula model","D Brewer-Nash model"], correct:2, explanation:"The Bell-LaPadula model enforces confidentiality through two rules: Simple Security (no read up — subjects cannot read objects at higher classification) and Star Property (no write down — subjects cannot write to objects at lower classification), preventing unauthorized disclosure of classified information." },
  { id:30252, domain:3, level:2, question:"Which of the following BEST describes 'defense in depth'?", options:["A Using the most advanced security technologies available","B Implementing multiple overlapping layers of security controls so failure of any one control does not lead to compromise","C Focusing security investments on the most critical systems","D Deploying security controls in sequence rather than simultaneously"], correct:1, explanation:"Defense in depth (layered security) implements multiple independent security controls such that an attacker must defeat multiple barriers to succeed — perimeter controls, network segmentation, host controls, application controls, and data controls each provide a layer that compensates for others' weaknesses." },
  { id:30253, domain:3, level:2, question:"Which of the following BEST describes a 'Trusted Platform Module' (TPM)?", options:["A A network security appliance for traffic inspection","B A dedicated hardware chip that stores cryptographic keys and provides hardware-based security functions including secure boot and attestation","C A trusted third-party certificate authority","D A software-based key management system"], correct:1, explanation:"TPM is a secure cryptoprocessor chip embedded in devices that provides hardware-based security functions: secure key storage (keys never leave the chip in plaintext), measured boot (detecting boot-time modifications), remote attestation (proving system integrity to external parties), and hardware random number generation." },
  { id:30254, domain:3, level:1, question:"Which of the following BEST describes the concept of 'open design' as a security architecture principle?", options:["A Security architectures should be openly documented for audit purposes","B Making security designs publicly available for transparency","C All security implementations should be open source","D Security should not depend on secrecy of the design, only on secrecy of keys and credentials"], correct:3, explanation:"Open design (Saltzer and Schroeder principle) holds that security should not depend on attackers not knowing the design — algorithms and mechanisms should be publicly scrutinized while secrets (keys, passwords) provide the actual security; security through obscurity alone is unreliable." },
  { id:30255, domain:4, level:1, question:"Which network model defines communication standards for interconnecting different network systems?", options:["A IEEE 802.11 standard","B NIST Framework","C OSI model","D TCP/IP model"], correct:2, explanation:"The OSI (Open Systems Interconnection) model defines a 7-layer framework (Physical, Data Link, Network, Transport, Session, Presentation, Application) for network communication, providing a conceptual model for understanding how data travels across networks and where security controls operate." },
  { id:30256, domain:4, level:2, question:"Which type of firewall inspects the state of network connections and allows return traffic for established connections?", options:["A Packet filtering firewall","B Stateful inspection firewall","C Application layer firewall","D Circuit-level gateway"], correct:1, explanation:"Stateful inspection firewalls maintain connection state tables tracking source/destination IPs, ports, and connection states — allowing return traffic for established connections without separate outbound rules, while blocking unsolicited inbound traffic that doesn't correspond to an established connection." },
  { id:30257, domain:3, level:2, question:"Which of the following BEST describes the 'Biba integrity model'?", options:["A A matrix-based access control model for database integrity","B No read up, no write down — enforcing confidentiality","C Separation of duties for data modification operations","D No write up, no read down — enforcing integrity by preventing lower-integrity subjects from contaminating higher-integrity objects"], correct:3, explanation:"Biba enforces integrity through two rules: Simple Integrity (no read down — subjects cannot read objects at lower integrity to prevent contamination), and Star Integrity Property (no write up — subjects cannot write to objects at higher integrity to prevent corruption of trusted data)." },
  { id:30258, domain:4, level:2, question:"Which network attack exploits ARP's stateless nature to redirect traffic to an attacker's device?", options:["A ARP spoofing/poisoning","B BGP hijacking","C MAC flooding","D DNS poisoning"], correct:0, explanation:"ARP spoofing exploits ARP's lack of authentication — an attacker sends gratuitous ARP replies associating their MAC address with a legitimate IP address, causing network devices to send traffic to the attacker instead of the legitimate host, enabling man-in-the-middle attacks and traffic interception." },
  { id:30259, domain:3, level:1, question:"Which cryptographic algorithm is asymmetric and widely used for secure key exchange and digital signatures?", options:["A RSA","B AES","C 3DES","D SHA-256"], correct:0, explanation:"RSA (Rivest-Shamir-Adleman) is an asymmetric algorithm using public/private key pairs — the public key encrypts or verifies, the private key decrypts or signs; used for key exchange, digital signatures, and certificate-based authentication in TLS, SSH, and other protocols." },
  { id:30260, domain:4, level:2, question:"Which network security control operates at Layer 7 and can inspect HTTP traffic to detect and block web application attacks?", options:["A Network-based IDS","B Web application firewall (WAF)","C VPN concentrator","D Stateful firewall"], correct:1, explanation:"WAFs operate at the application layer (Layer 7), inspecting HTTP/HTTPS request and response content to detect and block web application attacks (OWASP Top 10: SQL injection, XSS, CSRF, etc.) that packet-filtering and stateful firewalls cannot see because they only examine lower-layer headers." },
  { id:30261, domain:3, level:3, question:"An organization is implementing a public key infrastructure (PKI). Which PKI component is responsible for issuing digital certificates?", options:["A Key Escrow server","B Certificate Revocation List (CRL)","C Registration Authority (RA)","D Certificate Authority (CA)"], correct:3, explanation:"The Certificate Authority (CA) is the trusted entity that issues digital certificates — verifying the identity of requestors (or delegating to an RA) and signing certificates with its private key, binding public keys to identities in a way that relying parties can verify." },
  { id:30262, domain:4, level:1, question:"Which protocol provides authentication, integrity, and optional encryption for IP communications at the network layer?", options:["A IPSec","B SSL/TLS","C SSH","D HTTPS"], correct:0, explanation:"IPSec (Internet Protocol Security) operates at Layer 3 to provide authentication (verifying packet origin), integrity (detecting modification), and optional confidentiality (encryption) for IP communications — used in VPNs and to secure host-to-host communications without modifying applications." },
  { id:30263, domain:3, level:2, question:"Which of the following BEST describes 'security through obscurity' and why it is considered insufficient?", options:["A It is a strong defense when combined with other controls","B It is the practice of hiding security controls from attackers","C Relying on keeping design or implementation details secret as the primary security mechanism — insufficient because secrets are eventually disclosed and the security fails completely when they are","D It involves encrypting system configurations"], correct:2, explanation:"Security through obscurity uses secrecy of design/implementation as the primary defense — insufficient because secrets inevitably leak (disgruntled employees, reverse engineering, vulnerabilities), and when the secret is revealed, all security is lost; it can be a supplementary measure but never the primary defense." },
  { id:30264, domain:4, level:2, question:"Which type of network attack occurs when a system sends more data to a target than its buffer can hold, potentially overwriting adjacent memory?", options:["A Buffer overflow","B Format string attack","C Race condition","D SQL injection"], correct:0, explanation:"Buffer overflow attacks send more data than a buffer is sized to hold, overwriting adjacent memory — on the stack, this can overwrite return addresses to redirect execution to attacker-controlled code; memory-safe programming and stack canaries, ASLR, and DEP are primary defenses." },
  { id:30265, domain:3, level:1, question:"Which hashing algorithm produces a 256-bit digest and is widely recommended as secure for integrity verification?", options:["A DES","B SHA-256","C MD5","D SHA-1"], correct:1, explanation:"SHA-256 (SHA-2 family) produces a 256-bit cryptographic hash and is currently recommended for integrity verification — MD5 and SHA-1 are cryptographically broken with known collision attacks; SHA-256 and SHA-3 are the current standards for security-critical applications." },
  { id:30266, domain:4, level:3, question:"A network engineer proposes implementing VLANs to segment the network for security purposes. What is the MOST significant limitation of relying solely on VLANs for network security?", options:["A VLANs are too expensive to implement in large environments","B VLANs require proprietary hardware that increases costs","C VLAN hopping attacks can allow traffic to cross VLAN boundaries, and VLANs do not provide encryption or authentication between segments","D VLANs cannot support modern wireless networks"], correct:2, explanation:"VLAN-based segmentation has significant limitations: VLAN hopping (double-tagging attacks) can bypass isolation; VLANs provide no encryption so traffic is visible to anyone with physical access; and misconfigured trunk ports can expose all VLANs — requiring firewalls between VLANs for true security isolation." },
  { id:30267, domain:3, level:2, question:"Which of the following BEST describes 'key management' in cryptographic systems?", options:["A Managing physical access to servers containing cryptographic modules","B The complete lifecycle of cryptographic keys including generation, distribution, storage, rotation, retirement, and secure destruction","C Managing employee access to encrypted systems","D The administrative process of assigning encryption keys to users"], correct:1, explanation:"Key management encompasses the entire key lifecycle: generating keys with sufficient randomness, distributing them securely, storing them protected from unauthorized access, rotating them regularly, keeping them available for authorized use, and securely destroying them when no longer needed — the most operationally challenging aspect of cryptography." },
  { id:30268, domain:4, level:1, question:"Which type of intrusion detection system analyzes network traffic for patterns matching known attack signatures?", options:["A Signature-based IDS","B Stateful protocol analysis IDS","C Behavioral IDS","D Anomaly-based IDS"], correct:0, explanation:"Signature-based IDS compares observed traffic against a database of known attack patterns — effective against known attacks with low false positives, but unable to detect novel attacks not in the signature database; anomaly-based systems can detect novel attacks but generate more false positives." },
  { id:30269, domain:3, level:2, question:"Which of the following BEST describes the concept of 'cryptographic key escrow'?", options:["A Sharing encryption keys between multiple users in a group","B Using multiple encryption keys to protect the same data simultaneously","C Storing backup encryption keys with a trusted third party to enable data recovery if the primary key is lost","D Government access to all private encryption keys"], correct:2, explanation:"Key escrow involves depositing copies of encryption keys with a trusted third party (escrow agent) — enabling data recovery if the primary key is lost or unavailable; enterprise key escrow ensures business continuity by allowing authorized recovery of encrypted data when key holders are unavailable." },
  { id:30270, domain:4, level:2, question:"Which network attack sends unsolicited packets to exhaust a victim's resources, making legitimate services unavailable?", options:["A Phishing","B Denial of Service (DoS)","C Man-in-the-middle","D Eavesdropping"], correct:1, explanation:"Denial of Service attacks overwhelm a target's resources (bandwidth, CPU, memory, connection tables) with malicious traffic, preventing legitimate users from accessing services; DDoS (Distributed DoS) uses many compromised systems simultaneously to generate overwhelming volume." },
  { id:30271, domain:3, level:1, question:"Which type of encryption uses different keys for encryption and decryption?", options:["A Asymmetric encryption","B Stream cipher encryption","C Symmetric encryption","D Hashing"], correct:0, explanation:"Asymmetric encryption uses a mathematically linked key pair — data encrypted with the public key can only be decrypted with the corresponding private key (encryption), and data signed with the private key can be verified with the public key (authentication); slower than symmetric but solves key distribution." },
  { id:30272, domain:4, level:2, question:"Which protocol provides secure, encrypted remote terminal access to systems over an untrusted network?", options:["A SSH (Secure Shell)","B Telnet","C FTP","D SNMP"], correct:0, explanation:"SSH provides encrypted, authenticated remote terminal access, replacing insecure protocols like Telnet (which transmits in cleartext including passwords); SSH also provides secure file transfer (SFTP/SCP) and port forwarding, and uses public key cryptography for strong authentication." },
  { id:30273, domain:3, level:3, question:"An organization is implementing a PKI. The root CA's private key must be stored with the HIGHEST security. Which storage approach is MOST appropriate?", options:["A Distributed across multiple geographically separated cloud providers","B Hardware Security Module (HSM) in an air-gapped, physically secured facility, used only for ceremonial signing of subordinate CA certificates","C In a password manager accessible to the PKI administrators","D Encrypted file on a secure server in the primary data center"], correct:1, explanation:"Root CA private key protection requires maximum security: HSMs prevent key extraction even by administrators, air-gapping eliminates network-based attacks, physical security prevents physical access, and ceremonial use (only for signing subordinate CAs, which then issue certificates) minimizes exposure — compromise of the root CA invalidates the entire PKI." },
  { id:30274, domain:4, level:1, question:"Which network security protocol uses certificates to establish encrypted connections between web browsers and servers?", options:["A Kerberos","B DNSSEC","C IPSec","D TLS (Transport Layer Security)"], correct:3, explanation:"TLS (successor to SSL) authenticates servers (and optionally clients) using digital certificates, negotiates encryption algorithms, establishes shared session keys, and provides encrypted channels between web browsers and servers — the foundation of HTTPS and used by many other protocols for transport security." },
  { id:30275, domain:3, level:2, question:"Which of the following BEST describes the 'Clark-Wilson model' of security?", options:["A A model for access control in discretionary access control systems","B A model enforcing data integrity through well-formed transactions and separation of duties for commercial applications","C A model focusing on data confidentiality in multilevel systems","D A model for network security policy enforcement"], correct:1, explanation:"Clark-Wilson enforces integrity in commercial systems through constrained data items (CDIs) that can only be modified through transformation procedures (TPs) verified to maintain integrity, and requiring separation of duties by preventing subjects from directly accessing CDIs — designed for commercial environments where integrity matters more than confidentiality." },
  { id:30276, domain:4, level:2, question:"Which wireless security protocol is currently considered the MOST secure for enterprise Wi-Fi authentication?", options:["A WPA2 with PSK","B WEP (Wired Equivalent Privacy)","C WPA3-Enterprise with 802.1X and EAP-TLS","D WPA (Wi-Fi Protected Access)"], correct:2, explanation:"WPA3-Enterprise with 802.1X and EAP-TLS provides the strongest wireless security: 802.1X requires individual authentication rather than shared keys, EAP-TLS uses mutual certificate-based authentication, and WPA3's SAE and 192-bit security mode protect against even sophisticated attacks; WEP is broken, WPA has vulnerabilities, WPA2-PSK is vulnerable to offline dictionary attacks." },
  { id:30277, domain:3, level:1, question:"What is the PRIMARY security benefit of using a 'salt' when storing passwords?", options:["A Salts encrypt passwords more strongly than hashing alone","B Salts prevent brute force attacks on individual passwords","C Salts prevent rainbow table and precomputation attacks by adding unique random data to each password before hashing, ensuring identical passwords produce different hashes","D Salts speed up password verification"], correct:2, explanation:"A cryptographic salt is unique random data added to each password before hashing — identical passwords produce different hashes (so database compromise reveals no password relationships), and rainbow tables (precomputed hash lookup tables) cannot be used since separate tables would be needed for every possible salt value." },
  { id:30278, domain:4, level:2, question:"Which network security control examines data flowing in and out of an organization's network, detecting and preventing sensitive information from being transmitted unauthorized?", options:["A Network Access Control","B Data Loss Prevention (DLP)","C Web Application Firewall","D Intrusion Detection System"], correct:1, explanation:"DLP systems inspect network traffic, email, and other channels for sensitive data patterns (PII, PHI, credit card numbers, proprietary data), blocking or alerting on unauthorized transmission — preventing data exfiltration and inadvertent disclosure through policy enforcement at the network boundary." },
  { id:30279, domain:3, level:2, question:"Which of the following BEST describes a 'hardware security module' (HSM)?", options:["A A network appliance that enforces hardware-level access controls","B A tamper-resistant hardware device that performs cryptographic operations and stores cryptographic keys in a secure, non-extractable manner","C A hardware-based random number generator for cryptographic seeding","D A secure laptop for handling sensitive cryptographic operations"], correct:1, explanation:"HSMs are tamper-resistant hardware devices designed for cryptographic key management and cryptographic operations — keys are generated and stored within the HSM and cannot be extracted in plaintext; physical tamper detection destroys keys if the device is opened; HSMs achieve FIPS 140-2 Level 3+ validation." },
  { id:30280, domain:4, level:1, question:"What does the term 'DMZ' (demilitarized zone) refer to in network security?", options:["A A network zone completely isolated from all external traffic","B A military-grade secure network segment","C A perimeter network segment isolated from both the internet and the internal network, hosting services that must be publicly accessible","D A zone where all security controls have been disabled for testing"], correct:2, explanation:"A DMZ is a segmented network zone between the internet and the internal network, hosting public-facing servers (web, email, DNS) — isolated by firewalls on both sides so that compromise of a DMZ server doesn't provide direct access to the internal network, and the internal network's resources remain protected." },
  { id:30281, domain:3, level:3, question:"A security architect is evaluating whether to use symmetric or asymmetric encryption for bulk data encryption at rest. Which factor MOST strongly favors symmetric encryption for this use case?", options:["A Symmetric encryption doesn't require key management","B Symmetric encryption provides non-repudiation for stored data","C Symmetric encryption is significantly faster than asymmetric encryption for bulk data operations","D Symmetric encryption is more secure for large amounts of data"], correct:2, explanation:"Symmetric algorithms (AES) are orders of magnitude faster than asymmetric algorithms (RSA) for bulk data — RSA is computationally expensive for large data sets; hybrid approaches use asymmetric encryption only to exchange symmetric session keys, with symmetric encryption handling actual bulk data." },
  { id:30282, domain:4, level:2, question:"Which of the following attack types BEST describes sending malicious input to a web application's database query to manipulate or access unauthorized data?", options:["A Path traversal","B SQL injection","C Cross-site scripting (XSS)","D Cross-site request forgery (CSRF)"], correct:1, explanation:"SQL injection involves inserting malicious SQL code into user input that is incorporated into database queries without sanitization — allowing attackers to read unauthorized data, modify records, execute stored procedures, or even control the database server in severe cases." },
  { id:30283, domain:3, level:2, question:"Which of the following BEST describes 'stream cipher' encryption?", options:["A A cipher that uses multiple encryption streams simultaneously","B Encrypting data one bit or byte at a time using a pseudo-random keystream, suited for continuous data streams","C Encrypting data in fixed-size blocks","D Encryption that processes data as it streams across a network connection"], correct:1, explanation:"Stream ciphers generate a pseudo-random keystream that is XORed with plaintext one bit or byte at a time — suited for continuous data streams (real-time communications, wireless data) where block boundaries are inconvenient; RC4 (broken), ChaCha20, and Salsa20 are examples." },
  { id:30284, domain:4, level:3, question:"An organization is designing network segmentation for a new data center. Which approach provides the STRONGEST security isolation between critical and non-critical systems?", options:["A Software-defined networking with dynamic policy enforcement","B Virtual firewall appliances providing logical separation","C Physical network separation with dedicated hardware for each security zone and no shared network paths","D VLAN segmentation with ACLs between segments"], correct:2, explanation:"Physical network separation with dedicated hardware provides the strongest isolation — no shared cables, switches, or routers between security zones eliminates the risk of misconfigurations, VLAN hopping, firmware vulnerabilities, or shared hardware attacks that affect logical segmentation approaches." },
  { id:30285, domain:3, level:1, question:"Which of the following is NOT a key requirement of the NIST Cybersecurity Framework (CSF)?", options:["A Protect","B Certify","C Detect","D Identify"], correct:1, explanation:"The NIST CSF core consists of five functions: Identify, Protect, Detect, Respond, and Recover — 'Certify' is not one of the functions; the framework provides guidance for managing cybersecurity risk but is not a certification program." },
  { id:30286, domain:4, level:2, question:"Which of the following BEST describes 'network segmentation' as a security control?", options:["A Monitoring all network traffic at the segment boundaries","B Dividing a network into isolated segments using firewalls, VLANs, or routers to limit unauthorized lateral movement and contain security incidents","C Physically separating all network equipment","D Encrypting all network traffic between segments"], correct:1, explanation:"Network segmentation limits the blast radius of security incidents — if one segment is compromised, the attacker cannot freely move to other segments; it also enforces access controls at segment boundaries (requiring authentication/authorization to cross), and makes network traffic patterns more predictable for anomaly detection." },
  { id:30287, domain:3, level:2, question:"Which certificate validation process checks whether a specific certificate has been revoked before it expires?", options:["A Certificate pinning","B Certificate chain validation","C Certificate transparency log verification","D Certificate Revocation List (CRL) or OCSP (Online Certificate Status Protocol)"], correct:3, explanation:"CRLs and OCSP provide certificate revocation status — when a certificate's private key is compromised or the certificate is no longer trusted, the CA revokes it and lists it in the CRL or provides revocation status through OCSP; clients must check revocation status to ensure they're not trusting compromised certificates." },
  { id:30288, domain:4, level:1, question:"Which of the following BEST describes 'network address translation' (NAT) and its security implication?", options:["A NAT provides strong authentication for network connections","B NAT is a primary security defense against network attacks","C NAT translates private IP addresses to public IPs for internet routing, providing partial obscurity of internal network topology but not a true security control","D NAT encrypts network traffic between internal and external networks"], correct:2, explanation:"NAT hides internal network addressing from external parties (providing some obscurity) but is not a security control — it doesn't prevent attacks from the internet to exposed services, doesn't authenticate traffic, and can be confused with firewall protection; security comes from actual access controls, not address translation." },
  { id:30289, domain:3, level:2, question:"Which of the following BEST describes the 'principle of fail safe defaults'?", options:["A Systems should fail in a way that maximizes operational continuity","B Systems should automatically fail over to backup configurations","C Security systems should fail silently to avoid alerting attackers","D Access decisions should default to denial when an explicit permission doesn't exist — the system fails safely by refusing access rather than granting it"], correct:3, explanation:"Fail safe defaults mean the default access decision is 'deny' when no explicit permission exists — rather than allowing access when a rule is missing or a system fails, the system defaults to the secure (access denied) state; an open/permissive default creates security vulnerabilities when authorization systems fail." },
  { id:30290, domain:4, level:2, question:"Which network attack exploits DNS cache poisoning to redirect users to malicious websites?", options:["A Session hijacking","B DNS spoofing/cache poisoning","C IP spoofing","D BGP hijacking"], correct:1, explanation:"DNS cache poisoning inserts fraudulent DNS records into resolver caches — when users query for legitimate websites, their DNS resolver returns the attacker's IP address, redirecting them to malicious sites for phishing or malware delivery without users' knowledge; DNSSEC provides cryptographic protection against this attack." },
  { id:30291, domain:3, level:1, question:"Which of the following BEST describes the concept of 'perfect forward secrecy' (PFS) in cryptographic protocols?", options:["A Encryption that cannot be broken under any circumstances","B A key management technique ensuring keys are never reused","C Encryption providing perfect protection for future communications","D Each session uses ephemeral key exchange so that compromise of long-term keys cannot decrypt past session traffic"], correct:3, explanation:"PFS (now called forward secrecy) uses ephemeral key exchange (DHE or ECDHE) so each session establishes unique session keys independent of long-term private keys — if long-term keys are later compromised, recorded past sessions cannot be decrypted, protecting historical confidentiality." },
  { id:30292, domain:4, level:2, question:"Which network access control technology authenticates devices and users before allowing access to the network?", options:["A 802.1X (Port-based Network Access Control)","B ARP inspection","C VLAN tagging","D DHCP snooping"], correct:0, explanation:"802.1X is an IEEE standard for port-based network access control — devices connecting to a network port must authenticate using EAP before the port allows network access; authentication can be based on credentials, certificates, or other factors, verified by a RADIUS server." },
  { id:30293, domain:3, level:2, question:"Which of the following BEST describes the security concept of 'key stretching'?", options:["A Distributing cryptographic keys across multiple servers","B Using longer encryption keys for stronger security","C Extending key validity periods to reduce administrative overhead","D Applying computationally intensive operations to make brute-force attacks on weak passwords more expensive"], correct:3, explanation:"Key stretching algorithms (bcrypt, scrypt, Argon2, PBKDF2) apply iterative hashing to make each password guess computationally expensive — attackers must perform thousands/millions of operations per guess, making dictionary and brute-force attacks against password hashes impractically slow even on modern hardware." },
  { id:30294, domain:4, level:3, question:"An organization's firewall logs show thousands of connection attempts from varying source IPs to the same destination port on a critical server. The MOST likely attack type is:", options:["A A distributed port scan or distributed brute force attack","B SSL stripping attack","C SQL injection","D DNS cache poisoning"], correct:0, explanation:"Distributed connection attempts from many source IPs to the same port indicate a distributed scan (reconnaissance for open services) or distributed brute force/credential stuffing attack — using multiple sources to evade IP-based rate limiting and blocking; correlating distributed activity reveals the attack pattern." },
  { id:30295, domain:3, level:1, question:"Which term describes the use of both confidentiality and integrity protections in a single cryptographic operation?", options:["A Message authentication code","B Digital signature","C Certificate pinning","D Authenticated encryption (AE/AEAD)"], correct:3, explanation:"Authenticated Encryption with Associated Data (AEAD) — implemented by algorithms like AES-GCM and ChaCha20-Poly1305 — provides both encryption (confidentiality) and authentication (integrity) in a single pass, more efficient and less error-prone than combining separate confidentiality and integrity mechanisms." },
  { id:30296, domain:4, level:2, question:"Which of the following BEST describes the security purpose of 'network traffic analysis'?", options:["A Documenting network topology","B Measuring bandwidth utilization for capacity planning","C Optimizing network performance","D Detecting anomalous communication patterns, data exfiltration, lateral movement, and command-and-control communications"], correct:3, explanation:"Network traffic analysis (using flow data, packet inspection, and behavioral analytics) detects security threats visible in traffic patterns: unusual volumes or destinations (exfiltration), repeated internal connections (lateral movement), periodic beaconing (C2 communication), and protocol anomalies (covert channels)." },
  { id:30297, domain:3, level:2, question:"Which of the following BEST describes 'certificate pinning' as a security control?", options:["A Pinning certificates to specific IP addresses for connection validation","B Hard-coding expected certificate or public key values into applications so they reject connections using unexpected certificates, even if signed by trusted CAs","C Physically securing server certificates in tamper-resistant hardware","D Requiring physical token authentication for certificate issuance"], correct:1, explanation:"Certificate pinning prevents attacks using rogue certificates from trusted CAs (man-in-the-middle with fraudulent certs) — applications accept only the pinned certificate or public key, rejecting any other certificate even if signed by a legitimate CA; mobile apps and critical services use pinning for high-security connections." },
  { id:30298, domain:4, level:1, question:"Which of the following BEST describes the purpose of a 'honeypot' in network security?", options:["A A server trap designed to detect, deflect, and study attacker activity","B A network device that filters malicious traffic","C A security system monitoring legitimate user activity","D A backup system maintaining production data copies"], correct:0, explanation:"Honeypots are decoy systems designed to attract attackers — any interaction with a honeypot indicates malicious activity (legitimate users have no reason to access a decoy system), providing early warning of attacks, intelligence about attacker methods, and potentially delaying or deflecting attacks from real systems." },
  { id:30299, domain:3, level:3, question:"An organization must comply with requirements to provide encrypted communications while also enabling lawful interception. Which cryptographic architecture BEST addresses this conflict?", options:["A Prohibit end-to-end encryption entirely","B Weaken encryption to enable government decryption","C Use key escrow or key recovery systems that maintain copies of session keys accessible only through strictly controlled legal processes","D Implement backdoors in all encryption systems"], correct:2, explanation:"Key escrow for lawful interception stores copies of decryption keys with a trusted third party (potentially government-managed) that can only be accessed through legally authorized processes — theoretically balancing individual privacy with lawful access requirements, though this approach has significant security and policy controversy." },
  { id:30300, domain:4, level:2, question:"Which of the following BEST describes the security benefit of 'network microsegmentation' versus traditional VLAN-based segmentation?", options:["A Microsegmentation is cheaper to implement","B Microsegmentation applies workload-level security policies that follow workloads regardless of network location, enabling zero trust within the network","C Microsegmentation eliminates the need for firewalls","D Microsegmentation provides better network performance"], correct:1, explanation:"Microsegmentation applies security policies at the workload/VM level rather than the network segment level — policies follow workloads as they move, enable application-layer access controls between individual workloads in the same network segment, and eliminate the implicit trust that exists within a VLAN." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CISSP_C1 = QUESTIONS_CISSP_C1;
